import { NextResponse } from 'next/server';
import { createClient } from '@/lib/supabase/server';

export async function POST(request: Request) {
  const supabase = await createClient();
  const { data: { session } } = await supabase.auth.getSession();

  if (!session) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  try {
    const body = await request.json();
    const { name, category, location, phone, description, serviceMins } = body;

    if (!name || !category || !location) {
      return NextResponse.json({ error: 'Missing required fields' }, { status: 400 });
    }

    // Slugify name + city
    const slug = (name + '-' + location)
      .toLowerCase()
      .trim()
      .replace(/[^\w\s-]/g, '')
      .replace(/[\s_-]+/g, '-')
      .replace(/^-+|-+$/g, '');

    const businessData = {
      id: slug,
      name,
      category,
      location,
      phone,
      description,
      serviceMins: parseInt(serviceMins) || 15,
      owner_id: session.user.id,
      plan: 'free' as const,
      claim_status: 'claimed' as const,
      is_open: false,
      is_accepting_tokens: true,
      onboarding_step: 2
    };

    const { data, error } = await (supabase
      .from('businesses')
      .insert([businessData])
      .select()
      .single() as any);

    if (error) {
      // If slug exists, try appending random suffix once
      if (error.code === '23505') {
        const altSlug = `${slug}-${Math.floor(Math.random() * 1000)}`;
        const { data: altData, error: altError } = await (supabase
          .from('businesses')
          .insert([{ ...businessData, id: altSlug }])
          .select()
          .single() as any);

        if (altError) throw altError;
        return NextResponse.json(altData);
      }
      throw error;
    }

    return NextResponse.json(data);
  } catch (error: any) {
    console.error('Business creation error:', error);
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server";
import { rateLimit } from "@/lib/rateLimit";

export async function POST(req: NextRequest) {
  if (!rateLimit(req, 10, 60000)) {
    return NextResponse.json({ error: 'Too many requests' }, { status: 429 });
  }
  try {
    const { message, tokenNumber, currentlyServing, peopleAhead } = await req
      .json();
    const apiKey = process.env.GEMINI_API_KEY;

    // If no API key is configured, return smart fallback instead of crashing
    if (!apiKey) {
      return NextResponse.json({
        response: generateFallbackResponse(message, tokenNumber, peopleAhead),
        fallback: true,
      });
    }

    const prompt = `
      You are a helpful virtual assistant for "QueueLess India".
      The user asking the question is currently in a waiting line.
      Here is their context:
      - Their Token Number: ${tokenNumber}
      - Tokens Ahead of them: ${peopleAhead}
      - Expected wait time: ~${peopleAhead * 5} minutes left.

      Answer this user's question concisely, happily, and politely.
      Assume each person takes about 5 minutes to be served.

      User Question: "${message}"
    `;

    const response = await fetch(
      `https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=${apiKey}`,
      {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          contents: [{
            parts: [{ text: prompt }],
          }],
        }),
      },
    );

    if (!response.ok) {
      // API error ΓÇö fall back gracefully instead of 500
      console.error(`Gemini API error: ${response.status}`);
      return NextResponse.json({
        response: generateFallbackResponse(message, tokenNumber, peopleAhead),
        fallback: true,
      });
    }

    const data = await response.json();
    const responseText = data.candidates?.[0]?.content?.parts?.[0]?.text;

    if (!responseText) {
      return NextResponse.json({
        response: generateFallbackResponse(message, tokenNumber, peopleAhead),
        fallback: true,
      });
    }

    return NextResponse.json({ response: responseText, fallback: false });
  } catch (error) {
    console.error("AI Chat Error:", error);
    // Never show an error to the user ΓÇö always return a helpful fallback
    return NextResponse.json({
      response: generateFallbackResponse("", undefined, undefined),
      fallback: true,
    });
  }
}

function generateFallbackResponse(
  message: string,
  tokenNumber?: string,
  peopleAhead?: number,
): string {
  const lower = (message || "").toLowerCase();

  if (
    lower.includes("wait") || lower.includes("time") || lower.includes("long")
  ) {
    const estimate = peopleAhead
      ? `about ${peopleAhead * 5} minutes`
      : "shown on your token card";
    return `Your estimated wait time is ${estimate}. We update this in real-time as the queue moves.`;
  }
  if (lower.includes("cancel")) {
    return 'To cancel your token, go to your token page and tap "Cancel Token". Your spot will be released immediately.';
  }
  if (
    lower.includes("position") || lower.includes("number") ||
    lower.includes("ahead")
  ) {
    const pos = peopleAhead !== undefined
      ? `There are ${peopleAhead} people ahead of you.`
      : "Your current position is displayed on your token.";
    return `${pos} The number decreases as customers ahead of you are served.`;
  }
  if (
    lower.includes("fast") || lower.includes("skip") ||
    lower.includes("priority")
  ) {
    return "FastPass lets you skip ahead in the queue for a small fee. This feature is coming soon!";
  }
  if (
    lower.includes("hello") || lower.includes("hi") || lower.includes("hey")
  ) {
    const greeting = tokenNumber
      ? `Hi! You're token ${tokenNumber}.`
      : "Hi there!";
    return `${greeting} I'm here to help with your queue experience. Ask me about wait times, your position, or how things work.`;
  }
  return "I'm here to help with your queue experience. You can ask me about wait times, your position, or how to cancel your token.";
}

import { NextResponse } from 'next/server';
import Razorpay from 'razorpay';

export async function POST(request: Request) {
  try {
    const { orgId, serviceId, userId, amount, type } = await request.json();

    // ----------------------------------------------------------------------
    // RAZORPAY / MOCK CHECKOUT ENGINE
    // ----------------------------------------------------------------------
    const keyId = process.env.RAZORPAY_KEY_ID;
    const keySecret = process.env.RAZORPAY_KEY_SECRET;

    if (keyId && keySecret) {
      // Execute genuine Razorpay Sandbox/Live Order
      const rzp = new Razorpay({
        key_id: keyId || 'rzp_test_placeholder',
        key_secret: keySecret || 'placeholder_secret',
      });

      const options = {
        amount: Math.round(amount * 100), // convert INR to paise
        currency: "INR",
        receipt: `rcpt_${orgId}_${Date.now().toString().substring(6)}`
      };

      const order = await rzp.orders.create(options);

      return NextResponse.json({
        success: true,
        orderId: order.id,
        amount: order.amount,
        currency: order.currency,
        isMock: false
      });
    }

    // --- FALLBACK MOCK CHECKOUT (No Keys Provided) ---
    // Simulate network delay for realistic feel
    await new Promise((resolve) => setTimeout(resolve, 1500));

    // Generate a fake payment/checkout session ID
    const mockSessionId = `chk_mock_${Date.now()}_${Math.random().toString(36).substring(7)}`;

    return NextResponse.json({
      success: true,
      sessionId: mockSessionId,
      orderId: `order_mock_${Date.now()}`,
      url: `/customer/payment-success?session_id=${mockSessionId}&org=${orgId}&service=${serviceId}&type=${type}`,
      message: "Mock checkout session created successfully.",
      isMock: true
    });

  } catch (error) {
    console.error("Checkout Error:", error);
    return NextResponse.json(
      { success: false, error: "Failed to create checkout session" },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import Razorpay from 'razorpay';

const razorpay = new Razorpay({
  key_id: process.env.RAZORPAY_KEY_ID || 'rzp_test_placeholder',
  key_secret: process.env.RAZORPAY_KEY_SECRET || 'placeholder_secret',
});

export async function POST(req: NextRequest) {
  try {
    const { amount, businessId, businessName } = await req.json();

    if (!amount || !businessId) {
      return NextResponse.json({ error: 'Missing amount or businessId' }, { status: 400 });
    }

    // Platform fee: 2.5%
    const platformFee = Math.ceil(amount * 0.025);

    const options = {
      amount: amount * 100, // Razorpay expects paise
      currency: "INR",
      receipt: `fastpass_${businessId}_${Date.now()}`,
      notes: {
        businessId,
        businessName,
        platformFee: platformFee.toString()
      }
    };

    const order = await razorpay.orders.create(options);

    return NextResponse.json({
      orderId: order.id,
      amount: order.amount,
      currency: order.currency,
    });

  } catch (error: any) {
    console.error('Fast Pass Order Error:', error);
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import Razorpay from 'razorpay';
import { createClient } from '@supabase/supabase-js';

const razorpay = new Razorpay({
  key_id: process.env.RAZORPAY_KEY_ID || 'rzp_test_placeholder',
  key_secret: process.env.RAZORPAY_KEY_SECRET || 'placeholder_secret',
});

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL || 'https://placeholder.supabase.co';
const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY || 'placeholder';

const supabaseAdmin = createClient(supabaseUrl, supabaseKey);

export async function POST(req: NextRequest) {
  try {
    const { businessId, planId, customerData } = await req.json();

    if (!businessId || !planId) {
      return NextResponse.json({ error: 'Missing businessId or planId' }, { status: 400 });
    }

    // 1. Create/Retrieve Razorpay Customer (optional but recommended)
    // For simplicity, we'll create a subscription directly with plan_id

    // 2. Create Razorpay Subscription
    const subscription = await razorpay.subscriptions.create({
      plan_id: planId, // e.g., 'plan_growth_monthly'
      customer_notify: 1,
      total_count: 12, // For a year, or use 0 for indefinite
      notes: {
        business_id: businessId
      }
    });

    // 3. Save pending subscription info to Supabase
    const { error: dbError } = await supabaseAdmin
      .from('subscriptions')
      .insert({
        business_id: businessId,
        plan: planId.includes('growth') ? 'growth' : 'enterprise',
        razorpay_subscription_id: subscription.id,
        status: 'pending'
      });

    if (dbError) throw dbError;

    return NextResponse.json({
      subscriptionId: subscription.id,
      short_url: subscription.short_url,
    });

  } catch (error: any) {
    console.error('Razorpay Error:', error);
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import twilio from 'twilio';

/**
 * MOCK NOTIFICATION ENGINE API
 * Handles dispatching cross-channel operational alerts for QueueLess India.
 * If TWILIO_ACCOUNT_SID is provided, it uses the official Twilio SDK. Otherwise, mocks.
 */

// Init Twilio conditionally
const accountSid = process.env.TWILIO_ACCOUNT_SID;
const authToken = process.env.TWILIO_AUTH_TOKEN;
const fromNumber = process.env.TWILIO_PHONE_NUMBER;

const client = (accountSid && authToken) ? twilio(accountSid, authToken) : null;

interface NotifyRequest {
  tokenNumber: string;
  phoneNumber: string;
  orgName: string;
  event: 'JOINED' | 'APPROACHING' | 'CALLED';
  estimatedWaitMins?: number;
}

export async function POST(req: Request) {
  try {
    const body: NotifyRequest = await req.json();
    const { tokenNumber, phoneNumber, orgName, event, estimatedWaitMins } = body;

    let smsBody = "";

    switch (event) {
      case 'JOINED':
        smsBody = `Welcome to ${orgName}! Your QueueLess Token is ${tokenNumber}. Est wait: ${estimatedWaitMins} mins. Track live here: queueless.in/t/${tokenNumber}`;
        break;
      case 'APPROACHING':
        smsBody = `Alert: Your turn is approaching at ${orgName}! Token ${tokenNumber} is currently 3rd in line. Please head towards the waiting area.`;
        break;
      case 'CALLED':
        smsBody = `It's your turn! Token ${tokenNumber}, please proceed to the desk at ${orgName} immediately.`;
        break;
      default:
        smsBody = `Queue update for token ${tokenNumber} at ${orgName}.`;
    }

    if (client && fromNumber) {
      // Dispatch Real SMS
      await client.messages.create({
        body: smsBody,
        from: fromNumber,
        to: phoneNumber
      });
      console.log(`[TWILIO] SMS Sent to ${phoneNumber}: ${smsBody}`);
    } else {
      // Log the simulated mock message to the server console
      console.log('\n--- SIMULATED NOTIFICATION DISPATCH (No Twilio Keys) ---');
      console.log(`Channel: SMS & WhatsApp`);
      console.log(`To: ${phoneNumber}`);
      console.log(`Payload: ${smsBody}`);
      console.log('-------------------------------------------------------\n');

      // Simulate delay
      await new Promise(resolve => setTimeout(resolve, 800));
    }

    return NextResponse.json({
      success: true,
      message: "Notification dispatched successfully",
      deliveredTo: phoneNumber,
      eventTriggered: event,
      timestamp: new Date().toISOString()
    });

  } catch (error) {
    console.error("Failed to parse notification payload", error);
    return NextResponse.json(
      { success: false, error: "Invalid request format" },
      { status: 400 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";
import { rateLimit } from "@/lib/rateLimit";

export async function POST(req: NextRequest) {
  // Rate limit: 5 requests per minute per IP
  if (!rateLimit(req, 5, 60000)) {
    return NextResponse.json({ error: 'Too many requests' }, { status: 429 });
  }

  try {
    const body = await req.json();
    const supabase = await createClient();

    // Extract authenticated user server-side (don't trust client-sent userId)
    const { data: { user } } = await supabase.auth.getUser();

    // If user is authenticated, always use their server-verified ID
    // If not authenticated (guest join), userId stays null
    const secureBody = {
      ...body,
      userId: user?.id ?? body.userId ?? null,
    };

    // Proxy to the Supabase Edge Function
    const { data, error } = await supabase.functions.invoke("generate-token", {
      body: secureBody,
    });

    if (error) {
       console.error("Edge function error:", error);
       return NextResponse.json({ error: error.message }, { status: 400 });
    }

    return NextResponse.json({
      ...data,
      id: data.id,
      orgId: data.orgId
    });
  } catch (error: any) {
    console.error("Queue join API error:", error);
    return NextResponse.json({ error: error.message || "Internal Server Error" }, { status: 500 });
  }
}

import { createClient } from "@supabase/supabase-js";
import { NextResponse } from "next/server";

export async function POST(req: Request) {
  try {
    const { orgId } = await req.json();

    if (!orgId) {
      return NextResponse.json({ error: "Missing orgId" }, { status: 400 });
    }

    // Initialize admin client to bypass RLS
    const supabaseAdmin = createClient(
      process.env.NEXT_PUBLIC_SUPABASE_URL!,
      process.env.SUPABASE_SERVICE_ROLE_KEY!,
      {
        auth: {
          autoRefreshToken: false,
          persistSession: false,
        },
      }
    );

    // 1. Get current queue
    const { data: queue, error: qErr } = await supabaseAdmin
      .from("queues")
      .select("*")
      .eq("org_id", orgId)
      .eq("session_date", new Date().toISOString().split("T")[0])
      .eq("is_active", true)
      .single();

    if (qErr || !queue) {
      return NextResponse.json({ error: "No active queue found" }, { status: 404 });
    }

    // 2. Mark current serving token as SERVED if it exists
    if (queue.currently_serving_token_id) {
      await supabaseAdmin
        .from("tokens")
        .update({ 
          status: "SERVED",
          servedAt: new Date().toISOString()
        })
        .eq("id", queue.currently_serving_token_id);
    }

    // 3. Find next WAITING token
    const { data: nextToken, error: nErr } = await supabaseAdmin
      .from("tokens")
      .select("*")
      .eq("orgId", orgId)
      .eq("status", "WAITING")
      .order("createdAt", { ascending: true })
      .limit(1)
      .maybeSingle();

    if (nErr) throw nErr;

    let updatedQueue;
    if (nextToken) {
      // 4. Update next token to SERVING
      await supabaseAdmin
        .from("tokens")
        .update({ status: "SERVING" })
        .eq("id", nextToken.id);

      // 5. Update queue table
      const { data: uQ, error: uQErr } = await supabaseAdmin
        .from("queues")
        .update({
          currently_serving_token_id: nextToken.id,
          total_waiting: Math.max(0, queue.total_waiting - 1)
        })
        .eq("id", queue.id)
        .select()
        .single();

      if (uQErr) throw uQErr;
      updatedQueue = uQ;
    } else {
      // No more tokens waiting
      const { data: uQ, error: uQErr } = await supabaseAdmin
        .from("queues")
        .update({
          currently_serving_token_id: null,
          total_waiting: 0
        })
        .eq("id", queue.id)
        .select()
        .single();

      if (uQErr) throw uQErr;
      updatedQueue = uQ;
    }

    return NextResponse.json({ 
      success: true, 
      nextToken: nextToken || null,
      queue: updatedQueue
    });
  } catch (err: any) {
    console.error("Next token error:", err);
    return NextResponse.json({ error: err.message }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import crypto from 'crypto';
import { createClient } from '@supabase/supabase-js';

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL || 'https://placeholder.supabase.co';
const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY || 'placeholder';

const supabaseAdmin = createClient(supabaseUrl, supabaseKey);

export async function POST(req: NextRequest) {
  try {
    const { 
      razorpay_order_id, 
      razorpay_payment_id, 
      razorpay_signature,
      tokenData 
    } = await req.json();

    // 1. Verify Signature
    const body = razorpay_order_id + "|" + razorpay_payment_id;
    const expectedSignature = crypto
      .createHmac('sha256', process.env.RAZORPAY_KEY_SECRET || '')
      .update(body.toString())
      .digest('hex');

    if (expectedSignature !== razorpay_signature) {
      return NextResponse.json({ error: 'Invalid payment signature' }, { status: 400 });
    }

    // 2. Create Priority Token
    // We invoke the generate-token edge function but with isPriority: true
    // Or directly insert if permissions allow, but usually generate-token handles numbering logic
    const { data: token, error: tokenError } = await supabaseAdmin.functions.invoke("generate-token", {
      body: { 
        ...tokenData, 
        isPriority: true,
        paymentId: razorpay_payment_id
      }
    });

    if (tokenError) throw tokenError;

    // 3. Log Fast Pass Transaction
    await supabaseAdmin.from('fastpass_logs').insert({
      business_id: tokenData.orgId,
      token_id: token.id,
      amount: tokenData.amount,
      payment_id: razorpay_payment_id
    });

    return NextResponse.json({
      success: true,
      tokenId: token.id,
      tokenNumber: token.tokenNumber
    });

  } catch (error: any) {
    console.error('Fast Pass Verification Error:', error);
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import crypto from 'crypto';
import { createClient } from '@supabase/supabase-js';

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL || 'https://placeholder.supabase.co';
const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY || 'placeholder';

const supabaseAdmin = createClient(supabaseUrl, supabaseKey);

export async function POST(req: NextRequest) {
  try {
    const body = await req.text();
    const signature = req.headers.get('x-razorpay-signature');
    const secret = process.env.RAZORPAY_WEBHOOK_SECRET || '';

    if (!signature) {
      return NextResponse.json({ error: 'No signature' }, { status: 400 });
    }

    const expectedSignature = crypto
      .createHmac('sha256', secret)
      .update(body)
      .digest('hex');

    if (expectedSignature !== signature && process.env.NODE_ENV !== 'development') {
      return NextResponse.json({ error: 'Invalid signature' }, { status: 400 });
    }

    const event = JSON.parse(body);
    const { payload } = event;

    console.log('Razorpay Webhook Event:', event.event);

    switch (event.event) {
      case 'subscription.activated':
      case 'subscription.charged': {
        const sub = payload.subscription.entity;
        const businessId = sub.notes.business_id;
        const planId = sub.plan_id;
        const planType = planId.includes('growth') ? 'growth' : 'enterprise';

        // Update Subscriptions Table
        await supabaseAdmin
          .from('subscriptions')
          .update({
            status: 'active',
            current_period_end: new Date(sub.current_end * 1000).toISOString(),
            updated_at: new Date().toISOString()
          })
          .eq('razorpay_subscription_id', sub.id);

        // Update Business Plan
        await supabaseAdmin
          .from('businesses')
          .update({ plan: planType })
          .eq('id', businessId);

        break;
      }

      case 'subscription.cancelled':
      case 'subscription.halted': {
        const sub = payload.subscription.entity;
        const businessId = sub.notes.business_id;

        await supabaseAdmin
          .from('subscriptions')
          .update({ status: 'cancelled', updated_at: new Date().toISOString() })
          .eq('razorpay_subscription_id', sub.id);

        await supabaseAdmin
          .from('businesses')
          .update({ plan: 'free' })
          .eq('id', businessId);

        break;
      }
    }

    return NextResponse.json({ received: true });
  } catch (err: any) {
    console.error('Webhook Error:', err.message);
    return NextResponse.json({ error: err.message }, { status: 500 });
  }
}

