import React from 'react';
import { Metadata, ResolvingMetadata } from 'next';
import PublicBusinessClient from '@/components/Business/PublicBusinessClient';
import { notFound } from 'next/navigation';
import LanguageSelector from '@/components/LanguageSelector';
import { createClient } from '@/lib/supabase/server'

interface Props {
  params: { businessId: string };
}

// --- SERVER SIDE SEO METADATA ---
export async function generateMetadata({ params }: { params: { businessId: string } }): Promise<Metadata> {
  const supabase = await createClient()
  const { data: business } = await supabase
    .from('businesses')
    .select('name, category, location, address, avg_rating')
    .eq('id', params.businessId)
    .single() as any

  if (!business) return { title: 'Business Not Found' }

  const location = business.address || business.location || 'India'
  const title = `${business.name} ΓÇö Queue Token & Wait Time | QueueLess`
  const description = `Join the digital queue at ${business.name} in ${location}. Get your token on your phone ΓÇö no waiting in line. Current wait time and token status available.`

  return {
    title,
    description,
    keywords: [
      `${business.name} queue`,
      `${business.name} token`,
      `${business.category?.toLowerCase()} queue ${location}`,
      `skip queue ${location}`,
    ],
    openGraph: {
      title,
      description,
      url: `https://queueless-india.vercel.app/b/${params.businessId}`,
      type: 'website',
    },
    alternates: {
      canonical: `https://queueless-india.vercel.app/b/${params.businessId}`,
    },
  }
}

export default async function PublicBusinessPage({ params }: Props) {
  const { businessId } = params;
  const supabase = await createClient();

  // 1. Fetch Business Initial Data (SSR)
  const { data: business, error: bizErr } = await (supabase
    .from('businesses')
    .select('*')
    .eq('id', businessId)
    .single() as any);

  if (bizErr || !business) {
    notFound();
  }

  // 2. Fetch Initial Tokens for stats
  const { count: waitingCount } = await supabase
    .from('tokens')
    .select('*', { count: 'exact', head: true })
    .eq('orgId', businessId)
    .eq('status', 'WAITING')
    .gte('createdAt', new Date().toISOString().split('T')[0]) as any;

  // 3. Fetch Last 5 Reviews
  const { data: reviews } = await supabase
    .from('reviews')
    .select('*')
    .eq('business_id', businessId)
    .order('created_at', { ascending: false })
    .limit(5) as any;

  const jsonLd = {
    '@context': 'https://schema.org',
    '@type': 'LocalBusiness',
    name: business.name,
    description: `Digital queue management at ${business.name}`,
    url: `https://queueless-india.vercel.app/b/${business.id}`,
    address: {
      '@type': 'PostalAddress',
      streetAddress: business.address || '',
      addressLocality: business.location || '',
      addressCountry: 'IN',
    },
    ...(business.latitude && business.longitude && {
      geo: {
        '@type': 'GeoCoordinates',
        latitude: business.latitude,
        longitude: business.longitude,
      },
    }),
    ...(business.avg_rating && {
      aggregateRating: {
        '@type': 'AggregateRating',
        ratingValue: business.avg_rating,
        reviewCount: business.total_reviews || 1,
        bestRating: 5,
        worstRating: 1,
      },
    }),
  }

  return (
    <>
      <script
        type="application/ld+json"
        dangerouslySetInnerHTML={{ __html: JSON.stringify(jsonLd) }}
      />
      <main className="min-h-screen bg-background relative">
       {/* Regional Language Support (UX-2) */}
       <div className="absolute top-6 right-6 z-[100]">
          <LanguageSelector variant="compact" />
       </div>

       <PublicBusinessClient 
         business={business} 
         initialWaitingCount={waitingCount || 0} 
         initialReviews={reviews || []}
       />
    </main>
    </>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Ticket, Clock, History, Search, ChevronRight, 
  MapPin, LogOut, User, Bell, Star, ArrowRight, Activity, QrCode, LayoutDashboard
} from 'lucide-react';
import { createClient } from '@/lib/supabase/client';
import { useAuth } from '@/context/AuthContext';

const supabase = createClient();
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import GlassCard from '@/components/ui/GlassCard';
import CountUp from '@/components/ui/CountUp';
import LiveIndicator from '@/components/ui/LiveIndicator';

export default function CustomerDashboard() {
  const { user, userRole, signOut } = useAuth();
  const router = useRouter();
  const [activeTokens, setActiveTokens] = useState<any[]>([]);
  const [historyTokens, setHistoryTokens] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!user) {
      router.push('/customer');
      return;
    }

    const fetchData = async () => {
      setLoading(true);
      
      // Fetch Active Tokens
      const { data: active } = await supabase
        .from('tokens')
        .select('*, businesses(name, address, category)')
        .eq('userId', user.id)
        .in('status', ['WAITING', 'SERVING'])
        .order('createdAt', { ascending: false });

      // Fetch History
      const { data: history } = await supabase
        .from('tokens')
        .select('*, businesses(name, avg_rating)')
        .eq('userId', user.id)
        .in('status', ['SERVED', 'CANCELLED'])
        .order('createdAt', { ascending: false })
        .limit(10);

      setActiveTokens(active || []);
      setHistoryTokens(history || []);
      setLoading(false);
    };

    fetchData();

    // Realtime subscription for status changes
    const channel = supabase
      .channel(`customer_tokens_${user.id}`)
      .on('postgres_changes', {
        event: 'UPDATE',
        schema: 'public',
        table: 'tokens',
        filter: `userId=eq.${user.id}`
      }, () => {
        fetchData();
      });

    const handleVisibility = () => {
      if (document.hidden) {
        channel.unsubscribe();
      } else {
        channel.subscribe();
      }
    };

    channel.subscribe();
    document.addEventListener('visibilitychange', handleVisibility);

    return () => {
      document.removeEventListener('visibilitychange', handleVisibility);
      supabase.removeChannel(channel);
    };
  }, [user, router]);

  const handleLogout = async () => {
    await signOut();
    router.push('/');
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <div className="flex flex-col items-center gap-4">
          <div className="w-12 h-12 border-4 border-white/5 border-t-primary rounded-full animate-spin" />
          <p className="text-[10px] font-black uppercase tracking-widest text-zinc-500">Loading your world...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background text-white pb-32">
       
        {/* HEADER */}
        <header className="px-6 pt-12 pb-8 flex items-center justify-between sticky top-0 bg-background/80 bg-opacity-95 z-40 border-b border-white/5">
           <div>
             <h1 className="text-3xl font-black tracking-tighter">My Tokens</h1>
             <p className="text-zinc-500 text-xs font-bold uppercase tracking-widest mt-1">
                Logged in as {user?.phone || 'Guest'}
             </p>
           </div>
           
           <div className="flex items-center gap-3">
              {/* Role Switcher for Business Owners */}
              {userRole === "business_owner" && (
                <button 
                  onClick={() => router.push('/dashboard')}
                  className="w-10 h-10 rounded-xl bg-indigo-500/10 border border-indigo-500/20 flex items-center justify-center text-indigo-400 hover:bg-indigo-500/20 transition-all"
                  title="Switch to Business Mode"
                >
                  <LayoutDashboard size={18} />
                </button>
              )}
              
              <button 
                onClick={handleLogout}
                className="w-10 h-10 rounded-full bg-white/5 border border-white/10 flex items-center justify-center text-zinc-400 hover:text-white transition-colors"
                title="Sign Out"
              >
                <LogOut size={18} />
              </button>
           </div>
        </header>

         <main className="px-6 flex-1 flex flex-col py-8">
            {activeTokens.length === 0 && historyTokens.length === 0 ? (
              <motion.div 
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                className="flex-1 flex flex-col items-center justify-center text-center py-12"
              >
                 <div className="w-32 h-32 bg-primary/10 rounded-[3rem] flex items-center justify-center mb-8 border border-primary/20 relative">
                    <div className="absolute inset-0 bg-primary/20 blur-3xl rounded-full animate-pulse" />
                    <Ticket size={64} className="text-primary relative z-10" />
                 </div>
                 <h2 className="text-3xl font-black mb-4 tracking-tight leading-tight">You haven't joined<br/>any queues yet</h2>
                 <p className="text-zinc-500 text-sm font-medium mb-10 max-w-[280px] leading-relaxed">
                    Find a nearby hospital, bank, or temple and skip the wait with a digital token.
                 </p>
                 <div className="space-y-4 w-full max-w-xs">
                    <button 
                      onClick={() => router.push('/home')}
                      className="w-full btn-primary py-5 flex items-center justify-center gap-3 text-sm"
                    >
                       <Search size={18} /> Find a Queue Near Me
                    </button>
                    <button 
                      onClick={() => router.push('/customer/scanner')}
                      className="w-full py-5 rounded-2xl bg-white/5 border border-white/10 text-white font-black uppercase tracking-widest text-[10px] hover:bg-white/10 transition-all flex items-center justify-center gap-3"
                    >
                       <QrCode size={18} /> Scan QR Code
                    </button>
                 </div>
              </motion.div>
            ) : (
              <div className="space-y-8">
                 {/* ACTIVE TOKENS SECTION */}
                 <section>
                    <div className="flex items-center justify-between mb-4 px-2">
                       <h2 className="text-[10px] font-black uppercase tracking-widest text-primary flex items-center gap-2">
                         <Activity size={12} /> Active Queues
                       </h2>
                       <span className="bg-primary/10 text-primary text-[10px] px-2 py-0.5 rounded-md font-black">
                          {activeTokens.length} LIVE
                       </span>
                    </div>

                    <div className="space-y-4">
                       {activeTokens.length > 0 ? (
                         activeTokens.map(token => (
                           <motion.div 
                             key={token.id}
                             initial={{ opacity: 0, scale: 0.95 }}
                             animate={{ opacity: 1, scale: 1 }}
                             onClick={() => router.push(`/customer/queue/${token.orgId}/${token.id}`)}
                             className="cursor-pointer"
                           >
                              <GlassCard className="relative overflow-hidden group">
                                 {token.status === 'SERVING' && (
                                    <div className="absolute top-0 right-0 px-4 py-1 bg-emerald-500 text-black text-[10px] font-black uppercase tracking-widest rounded-bl-xl shadow-lg animate-pulse">
