"use client";

import { useEffect, useState } from "react";
import { createClient } from "@/lib/supabase/client";
import { motion, AnimatePresence } from "framer-motion";
import { 
  Users, Clock, Play, Pause, XCircle, 
  ChevronRight, Loader2, AlertCircle, RefreshCw,
  LogOut, LayoutDashboard
} from "lucide-react";
import { toast } from "sonner";
import GlassCard from "@/components/ui/GlassCard";
import { useRouter } from "next/navigation";

import { Business, Queue, Token } from "@/types/database";

export default function BusinessQueueManagement() {
  const supabase = createClient();
  const router = useRouter();
  const [business, setBusiness] = useState<Business | null>(null);
  const [queue, setQueue] = useState<Queue | null>(null);
  const [waitingTokens, setWaitingTokens] = useState<Token[]>([]);
  const [servingToken, setServingToken] = useState<Token | null>(null);
  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState(false);

  const fetchQueueData = async () => {
    try {
      // 1. Get logged in business (using admin_org from localStorage for now or checking owner_id)
      const adminOrgId = localStorage.getItem("admin_org");
      if (!adminOrgId) {
        router.push("/dashboard");
        return;
      }

      const { data: bData } = await supabase
        .from("businesses")
        .select("*")
        .eq("id", adminOrgId)
        .single();
      setBusiness(bData);

      // 2. Get today's queue
      const today = new Date().toISOString().split("T")[0];
      const { data: qData } = await supabase
        .from("queues")
        .select("*")
        .eq("org_id", adminOrgId)
        .eq("session_date", today)
        .eq("is_active", true)
        .maybeSingle();

      setQueue(qData);

      if (qData) {
        // 3. Get waiting tokens
        const { data: wTokens } = await supabase
          .from("tokens")
          .select("*")
          .eq("orgId", adminOrgId)
          .eq("status", "WAITING")
          .order("createdAt", { ascending: true })
          .limit(5);
        setWaitingTokens(wTokens || []);

        // 4. Get currently serving token
        if (qData.currently_serving_token_id) {
          const { data: sToken } = await supabase
            .from("tokens")
            .select("*")
            .eq("id", qData.currently_serving_token_id as string)
            .single();
          setServingToken(sToken as Token);
        } else {
          setServingToken(null);
        }
      }

      setLoading(false);
    } catch (err) {
      console.error(err);
      toast.error("Failed to load queue data");
    }
  };

  useEffect(() => {
    fetchQueueData();

    // REALTIME SUBSCRIPTIONS
    const adminOrgId = localStorage.getItem("admin_org");
    if (!adminOrgId) return;

    const channel = supabase
      .channel(`queue-staff-${adminOrgId}`)
      .on(
        "postgres_changes",
        { event: "*", schema: "public", table: "tokens", filter: `orgId=eq.${adminOrgId}` },
        () => fetchQueueData()
      )
      .on(
        "postgres_changes",
        { event: "UPDATE", schema: "public", table: "queues", filter: `org_id=eq.${adminOrgId}` },
        () => fetchQueueData()
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, []);

  const handleCallNext = async () => {
    setActionLoading(true);
    try {
      if (!business?.id) throw new Error("Business not found");
      const response = await fetch("/api/queue/next", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ orgId: business.id }),
      });
      const data = await response.json();
      if (!response.ok) throw new Error(data.error);

      toast.success(data.nextToken ? `Called ${data.nextToken.tokenNumber}` : "All tokens served!");
    } catch (err: any) {
      toast.error(err.message);
    } finally {
      setActionLoading(false);
    }
  };

  const togglePause = async () => {
    if (!queue?.id) return;
    const newState = !queue?.is_accepting_tokens;
    try {
      const { error } = await supabase
        .from("queues")
        .update({ is_accepting_tokens: newState })
        .eq("id", queue.id);
      if (error) throw error;
      toast.success(newState ? "Queue Resumed" : "Queue Paused");
    } catch (err: any) {
      toast.error(err.message);
    }
  };

  const handleCloseQueue = async () => {
    if (!confirm("Are you sure? This will cancel all remaining waiting tokens!")) return;
    try {
      // 1. Close queue
      if (queue?.id) {
        await supabase.from("queues").update({ is_active: false }).eq("id", queue.id);
      }

      // 2. Cancel waiting tokens
      if (business?.id) {
        await supabase
          .from("tokens")
          .update({ status: "CANCELLED" })
          .eq("orgId", business.id)
          .eq("status", "WAITING");
      }

      toast.success("Queue closed for today");
      fetchQueueData();
    } catch (err: any) {
      toast.error(err.message);
    }
  };

  const activateQueue = async () => {
    if (!business?.id) return;
    setActionLoading(true);
    try {
      const { data: qId, error } = await (supabase as any).rpc("activate_queue_for_today", {
        p_org_id: business.id
      });
      if (error) throw error;
      toast.success("Queue Activated!");
      fetchQueueData();
    } catch (err: any) {
      toast.error(err.message);
    } finally {
      setActionLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-[#0D0D14] flex flex-col items-center justify-center p-6 text-white font-sans">
        <Loader2 className="w-12 h-12 text-primary animate-spin mb-4" />
        <p className="text-[10px] font-black uppercase tracking-widest text-zinc-500">Initializing Terminal...</p>
      </div>
    );
  }

  if (!queue) {
    return (
      <div className="min-h-screen bg-[#0D0D14] text-white flex flex-col items-center justify-center p-6 gap-8">
        <div className="w-24 h-24 bg-white/5 rounded-[2.5rem] flex items-center justify-center border border-white/10">
          <XCircle size={48} className="text-zinc-600" />
        </div>
        <div className="text-center">
          <h2 className="text-2xl font-black tracking-tighter mb-2">No Active Queue</h2>
          <p className="text-zinc-500 text-sm max-w-xs font-medium">Everything is quiet today. Ready to start accepting tokens?</p>
        </div>
        <button 
          onClick={activateQueue}
          disabled={actionLoading}
          className="w-full max-w-xs py-5 bg-emerald-500 text-black font-black uppercase tracking-widest text-sm rounded-2xl flex items-center justify-center gap-3 hover:bg-emerald-400 transition-all shadow-xl shadow-emerald-500/20 active:scale-95"
        >
          {actionLoading ? <Loader2 className="animate-spin" /> : <><Play size={20} fill="currentColor" /> Activate for Today</>}
        </button>
        <button 
            onClick={() => router.push('/dashboard')}
            className="flex items-center gap-2 text-zinc-500 font-bold uppercase tracking-widest text-[10px]"
        >
            <LayoutDashboard size={14} /> Back to Hub
        </button>
      </div>
    );
  }

  const isPaused = !queue.is_accepting_tokens;

  return (
    <div className="min-h-screen bg-[#0D0D14] text-white flex flex-col font-sans p-6 safe-top overflow-hidden">
      {/* Header */}
      <header className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-xl font-black tracking-tight flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-primary animate-pulse" />
            {business?.name}
          </h1>
          <div className="flex items-center gap-2 mt-1">
             <span className={`text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded ${isPaused ? 'bg-amber-500/20 text-amber-500' : 'bg-emerald-500/20 text-emerald-500'}`}>
                {isPaused ? 'PAUSED' : 'OPEN'}
             </span>
             <span className="text-zinc-600 text-[10px] font-black uppercase tracking-widest leading-none">ΓÇó Staff View</span>
          </div>
        </div>
        <button 
          onClick={() => router.push('/dashboard')}
          className="p-3 rounded-2xl bg-white/5 border border-white/10 hover:bg-white/10 transition-colors"
        >
          <LayoutDashboard size={20} />
        </button>
      </header>

      {/* Hero: Now Serving */}
      <main className="flex-1 flex flex-col gap-6 max-w-2xl mx-auto w-full">

        <GlassCard className="p-10 rounded-[3rem] text-center relative overflow-hidden group">
          <div className="absolute inset-0 bg-primary/5 pointer-events-none group-hover:bg-primary/10 transition-colors" />
          <p className="text-xs font-black uppercase tracking-[0.3em] text-zinc-500 mb-6">Currently Serving</p>
          <div className="py-12 px-8 bg-black/40 border border-white/5 rounded-[2.5rem] inline-block w-full mb-8 relative">
            <AnimatePresence mode="wait">
              <motion.span 
                key={servingToken?.tokenNumber || "EMPTY"}
                initial={{ y: 20, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                exit={{ y: -20, opacity: 0 }}
                className="text-8xl sm:text-9xl font-black text-primary tracking-tighter"
              >
                {servingToken?.tokenNumber || "----"}
              </motion.span>
            </AnimatePresence>
            <p className="text-[10px] font-black text-zinc-600 mt-4 uppercase tracking-[0.2em]">{servingToken?.customerName || "Waiting..."}</p>
          </div>

          <div className="flex items-center justify-center gap-12 mb-10">
            <div className="text-center">
              <p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-1">Waiting</p>
              <p className="text-3xl font-black">{queue.total_waiting}</p>
            </div>
            <div className="w-px h-8 bg-white/10" />
            <div className="text-center">
              <p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-1">Est. Time</p>
              <p className="text-3xl font-black">~{queue.total_waiting * (business?.serviceMins || 5)}<span className="text-xs text-zinc-500 ml-1 font-bold">m</span></p>
            </div>
          </div>

          <button 
            onClick={handleCallNext}
            disabled={actionLoading}
            className="w-full h-24 mb-2 bg-[#00F5A0] text-black rounded-[2rem] flex items-center justify-center gap-4 font-black uppercase tracking-[0.2em] text-lg shadow-[0_20px_50px_rgba(0,245,160,0.3)] hover:scale-[1.02] active:scale-95 transition-all disabled:opacity-50 disabled:grayscale"
          >
            {actionLoading ? <Loader2 className="animate-spin w-8 h-8" /> : (
              <>
                <ChevronRight size={32} />
                Call Next Token
              </>
            )}
          </button>
        </GlassCard>

        {/* Next in Line */}
        <section>
          <div className="flex items-center justify-between mb-4 px-4">
             <h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em] flex items-center gap-2">
                <Users size={12} /> Next in Line
             </h3>
             <RefreshCw size={12} className="text-zinc-600 animate-pulse" />
          </div>
          <div className="flex gap-3 overflow-x-auto pb-4 px-2 scrollbar-none">
             {waitingTokens.length > 0 ? waitingTokens.map((t, idx) => (
                <div key={t.id} className="min-w-[120px] p-5 rounded-3xl bg-white/[0.03] border border-white/5 text-center">
                   <p className="text-xs font-black text-zinc-600 mb-1">#{idx + 1}</p>
                   <p className="text-xl font-black text-white">{t.tokenNumber}</p>
                </div>
             )) : (
                <div className="w-full p-8 rounded-3xl border border-dashed border-white/5 text-center">
                   <p className="text-xs font-bold text-zinc-700 uppercase">Waiting List is Empty</p>
                </div>
             )}
          </div>
        </section>

        {/* Footer Actions */}
        <footer className="grid grid-cols-2 gap-4 mt-auto pt-6">
          <button 
            onClick={togglePause}
            className={`flex-1 py-5 rounded-[2rem] border flex items-center justify-center gap-2 font-black uppercase tracking-widest text-[10px] transition-all
              ${isPaused 
                ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-500' 
                : 'bg-amber-500/10 border-amber-500/20 text-amber-500'
              }`}
          >
            {isPaused ? <Play size={16} fill="currentColor" /> : <Pause size={16} fill="currentColor" />}
            {isPaused ? 'Resume Queue' : 'Pause Queue'}
          </button>
          <button 
            onClick={handleCloseQueue}
            className="flex-1 py-5 rounded-[2rem] bg-red-500/10 border border-red-500/20 text-red-500 flex items-center justify-center gap-2 font-black uppercase tracking-widest text-[10px] hover:bg-red-500/20"
          >
            <XCircle size={16} /> Close Queue
          </button>
        </footer>

      </main>
    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';
import { createClient } from '@/lib/supabase/client';
import { motion, AnimatePresence } from 'framer-motion';

export default function DisplayBoard({ params }: { params: { businessId: string } }) {
  const supabase = createClient();
  const [business, setBusiness] = useState<any>(null);
  const [serving, setServing] = useState<any>(null);
  const [nextUp, setNextUp] = useState<any[]>([]);
  const [servedToday, setServedToday] = useState(0);
  const [totalWaiting, setTotalWaiting] = useState(0);
  const [time, setTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (!params.businessId) return;

    const fetchData = async () => {
      // Fetch business info
      const { data: biz } = await supabase
        .from('businesses')
        .select('*')
        .eq('id', params.businessId)
        .maybeSingle();
      if (biz) setBusiness(biz);

      // Fetch currently serving
      const { data: servingToken } = await supabase
        .from('tokens')
        .select('*')
        .eq('orgId', params.businessId)
        .eq('status', 'SERVING')
        .maybeSingle();
      setServing(servingToken);

      // Fetch next 5 waiting
      const { data: waiting } = await supabase
        .from('tokens')
        .select('*')
        .eq('orgId', params.businessId)
        .eq('status', 'WAITING')
        .order('createdAt', { ascending: true })
        .limit(5);
      setNextUp(waiting || []);
      setTotalWaiting(waiting?.length || 0);

      // Fetch served today count
      const todayStart = new Date();
      todayStart.setHours(0, 0, 0, 0);
      const { count: servedCount } = await supabase
        .from('tokens')
        .select('*', { count: 'exact', head: true })
        .eq('orgId', params.businessId)
        .eq('status', 'SERVED')
        .gte('servedAt', todayStart.toISOString());
      setServedToday(servedCount || 0);
    };

    fetchData();

    // Realtime subscription
    const channel = supabase
      .channel(`display-${params.businessId}`)
      .on('postgres_changes', {
        event: '*',
        schema: 'public',
        table: 'tokens',
        filter: `orgId=eq.${params.businessId}`,
      }, () => fetchData())
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, [params.businessId]);

  const isBusinessOpen = () => {
    if (!business) return false;
    const now = new Date();
    const dayOfWeek = now.getDay();
    const dayNamesShort = ["sun", "mon", "tue", "wed", "thu", "fri", "sat"];
    const dayKey = dayNamesShort[dayOfWeek];

    if (business.op_hours_json?.[dayKey]) {
      const shifts = business.op_hours_json[dayKey];
      if (shifts === null) return false;

      const currentTime = now.getHours() * 60 + now.getMinutes();
      return shifts.some((shift: { open: string; close: string }) => {
        const [sH, sM] = shift.open.split(":").map(Number);
        const [eH, eM] = shift.close.split(":").map(Number);
        return currentTime >= sH * 60 + sM && currentTime <= eH * 60 + eM;
      });
    }
    return true; 
  };

  const getTomorrowOpening = () => {
    if (!business?.op_hours_json) return null;
    const tomorrow = new Date();
    tomorrow.setDate(tomorrow.getDate() + 1);
    const dayNamesShort = ["sun", "mon", "tue", "wed", "thu", "fri", "sat"];
    const dayKey = dayNamesShort[tomorrow.getDay()];
    const shifts = business.op_hours_json[dayKey];
    if (!shifts || shifts.length === 0) return "Monday 09:00 AM"; // Default fallback
    return `${dayKey.charAt(0).toUpperCase() + dayKey.slice(1)} ${shifts[0].open}`;
  };

  const isOpen = isBusinessOpen();
  const isEmpty = !serving && nextUp.length === 0;

  return (
    <div className="min-h-screen bg-[#0a0a0f] text-white font-sans flex flex-col">
      {/* Header */}
      <header className="bg-gradient-to-r from-indigo-600 to-purple-600 px-8 py-4 flex items-center justify-between shadow-2xl relative z-10">
        <div className="flex items-center gap-6">
          {business?.logo_url ? (
            <img src={business.logo_url} alt={business.name} className="w-16 h-16 rounded-2xl object-cover border-2 border-white/20 shadow-lg" />
          ) : (
            <div className="w-16 h-16 rounded-2xl bg-white/10 flex items-center justify-center border-2 border-white/10">
              <span className="text-2xl font-black">Q</span>
            </div>
          )}
          <div>
            <h1 className="text-3xl font-black tracking-tight leading-none mb-1">{business?.name || 'QueueLess'}</h1>
            <p className="text-white/70 text-sm font-medium">{business?.location}</p>
          </div>
        </div>
        <div className="text-right">
          <p className="text-4xl font-black tabular-nums tracking-tight">
            {time.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true, timeZone: 'Asia/Kolkata' })}
          </p>
          <p className="text-white/60 text-xs uppercase tracking-widest font-bold">
            {time.toLocaleDateString('en-IN', { weekday: 'long', day: 'numeric', month: 'short', timeZone: 'Asia/Kolkata' })}
          </p>
        </div>
      </header>

      {/* Main Content */}
      <div className="flex-1 flex flex-col lg:flex-row gap-0 overflow-hidden relative">
        <AnimatePresence mode="wait">
          {isEmpty ? (
            <motion.div 
              key="empty-state"
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.95 }}
              className="flex-1 flex flex-col items-center justify-center p-8 relative overflow-hidden"
            >
               {/* Background Glows */}
               <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[600px] h-[600px] bg-indigo-500/10 rounded-full blur-[120px] -z-10" />
               <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[400px] h-[400px] bg-purple-500/10 rounded-full blur-[80px] -z-10 animate-pulse" />

               <div className="text-center relative z-10">
                  <div className="w-24 h-24 rounded-3xl bg-indigo-500/10 border border-indigo-500/20 flex items-center justify-center mx-auto mb-8 shadow-[0_0_50px_rgba(99,102,241,0.1)]">
                     <motion.div
                       animate={{ 
                         scale: [1, 1.1, 1],
                         rotate: [0, 5, -5, 0]
                       }}
                       transition={{ duration: 4, repeat: Infinity }}
                     >
                       <svg className="w-12 h-12 text-indigo-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                         <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                       </svg>
                     </motion.div>
                  </div>

                  <h2 className="text-6xl font-black text-white mb-4 tracking-tighter">Queue is Empty</h2>
                  <p className="text-2xl text-slate-500 font-medium max-w-lg mx-auto mb-10">
                    No active tokens at the moment. Your turn will be called immediately upon joining.
                  </p>

                  <div className="flex items-center justify-center gap-4">
                     <span className={`px-6 py-2 rounded-full text-xs font-black uppercase tracking-[0.2em] border ${isOpen ? 'bg-emerald-500/10 text-emerald-500 border-emerald-500/20' : 'bg-red-500/10 text-red-500 border-red-500/20'}`}>
                        {isOpen ? "Now Open" : "Queue Closed"}
                     </span>
                     {!isOpen && (
                       <span className="text-slate-500 text-xs font-black uppercase tracking-widest">
                         Opening {getTomorrowOpening()}
                       </span>
                     )}
                  </div>
               </div>

               <div className="absolute bottom-12 text-center w-full">
                  <p className="text-[10px] text-slate-600 font-black uppercase tracking-[0.5em]">Scan to join via QR Code</p>
               </div>
            </motion.div>
          ) : (
            <motion.div 
              key="main-display"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="flex-1 flex flex-col lg:flex-row"
            >
              {/* Currently Serving - Big */}
              <div className="flex-1 flex items-center justify-center p-12 bg-gradient-to-br from-indigo-950/20 via-transparent to-transparent">
                <AnimatePresence mode="wait">
                  <motion.div
                    key={serving?.tokenNumber || 'none'}
                    initial={{ y: 50, opacity: 0, scale: 0.9 }}
                    animate={{ y: 0, opacity: 1, scale: 1 }}
                    exit={{ y: -50, opacity: 0, scale: 0.9 }}
                    className="text-center"
                  >
                    <p className="text-[12px] font-black uppercase tracking-[0.4em] text-emerald-500 mb-6 drop-shadow-[0_0_15px_rgba(16,185,129,0.5)]">
                      Current Token
                    </p>
                    <div className="relative">
                      <p className="text-[16rem] font-black leading-none tracking-tighter text-white drop-shadow-2xl">
                        {serving?.tokenNumber || '---'}
                      </p>
                      <div className="absolute -inset-12 bg-indigo-500/5 rounded-full blur-[100px] -z-10" />
                    </div>
                    {serving?.customerName && (
                      <p className="text-3xl text-slate-400 mt-6 font-bold tracking-tight">{serving.customerName}</p>
                    )}
                    {serving && (
                      <div className="mt-8 inline-flex items-center gap-3 px-8 py-4 rounded-2xl bg-emerald-500/10 border border-emerald-500/20 shadow-lg">
                        <span className="w-4 h-4 rounded-full bg-emerald-500 animate-pulse shadow-[0_0_15px_#10b981]" />
                        <span className="text-emerald-400 font-black text-base uppercase tracking-widest">Please proceed to counter</span>
                      </div>
                    )}
                  </motion.div>
                </AnimatePresence>
              </div>

              {/* Next Up Panel */}
              <div className="lg:w-[450px] bg-white/[0.02] border-l border-white/5 p-10 flex flex-col">
                <div className="flex items-center justify-between mb-8">
                  <h2 className="text-[12px] font-black uppercase tracking-[0.3em] text-slate-500">
                    Coming Up Next
                  </h2>
                  <div className="px-3 py-1 bg-white/5 rounded-full border border-white/10">
                     <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{nextUp.length} Waiting</span>
                  </div>
                </div>

                <div className="space-y-4 flex-1">
                  <AnimatePresence>
                    {nextUp.map((token, i) => (
                      <motion.div
                        key={token.id}
                        initial={{ x: 100, opacity: 0 }}
                        animate={{ x: 0, opacity: 1 }}
                        exit={{ x: -100, opacity: 0 }}
                        transition={{ delay: i * 0.1 }}
                        className={`flex items-center justify-between p-6 rounded-[2rem] transition-all ${
                          i === 0
                            ? 'bg-indigo-600 text-white shadow-[0_20px_40px_rgba(79,70,229,0.2)]'
                            : 'bg-white/[0.03] border border-white/10'
                        }`}
                      >
                        <div className="flex items-center gap-6">
                          <span className={`text-4xl font-black ${i === 0 ? 'text-white' : 'text-indigo-400'}`}>
                            {token.tokenNumber}
                          </span>
                          <div>
                            <p className={`text-sm font-bold ${i === 0 ? 'text-white/80' : 'text-slate-500'}`}>
                              {token.customerName}
                            </p>
                            {i === 0 && <p className="text-[10px] font-black uppercase tracking-widest text-white/60 mt-0.5">Ready to serve</p>}
                          </div>
                        </div>
                      </motion.div>
                    ))}
                  </AnimatePresence>
                </div>

                {/* Queue Stats Overlay */}
                <div className="mt-10 grid grid-cols-2 gap-4">
                  <div className="bg-emerald-500/5 border border-emerald-500/10 rounded-3xl p-6 text-center shadow-lg">
                    <p className="text-4xl font-black text-emerald-400">{servedToday}</p>
                    <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest mt-2">Served Total</p>
                  </div>
                  <div className="bg-white/[0.03] border border-white/10 rounded-3xl p-6 text-center shadow-lg">
                    <p className="text-4xl font-black text-white">~{nextUp.length * (business?.serviceMins || 5)}m</p>
                    <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest mt-2">Est. Wait</p>
                  </div>
                </div>
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>

      {/* Footer */}
      <footer className="bg-white/5 border-t border-white/5 px-8 py-4 flex items-center justify-between relative z-10">
        <div className="flex items-center gap-2">
           <div className="w-1.5 h-1.5 rounded-full bg-indigo-500 animate-pulse" />
           <span className="text-[10px] text-slate-600 font-black uppercase tracking-[0.2em]">Live Feed Active</span>
        </div>
        <div className="flex items-center gap-4">
           <span className="text-[10px] text-slate-600 font-black uppercase tracking-widest border-r border-white/10 pr-4">Powered by QueueLess India</span>
           <span className="text-[10px] text-indigo-500/50 font-black uppercase tracking-widest">queueless.in</span>
        </div>
      </footer>
    </div>
  );
}

"use client";

import { useEffect } from "react";
import { AlertCircle, RefreshCcw, Home } from "lucide-react";
import Link from "next/link";
import { motion } from "framer-motion";

export default function GlobalError({
  error,
  reset,
}: {
  error: Error & { digest?: string };
  reset: () => void;
}) {
  useEffect(() => {
    // Log the error to an error reporting service if available
    console.error("Global Application Error:", error);
  }, [error]);

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 flex flex-col items-center justify-center p-6 text-center font-sans">
      <motion.div
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        className="max-w-md w-full bg-white dark:bg-slate-900 rounded-[2rem] p-8 shadow-2xl border border-rose-100 dark:border-rose-900/30"
      >
        <div className="w-20 h-20 bg-rose-100 dark:bg-rose-500/10 text-rose-500 rounded-full flex items-center justify-center mx-auto mb-6">
          <AlertCircle size={40} strokeWidth={2.5} />
        </div>

        <h1 className="text-2xl font-black text-slate-900 dark:text-white mb-2">
          Oops! Something broke.
        </h1>
        <p className="text-slate-500 dark:text-slate-400 mb-8 leading-relaxed">
          We encountered an unexpected error while trying to load this page. Don't worry, our team has been notified.
        </p>

        <div className="flex flex-col sm:flex-row gap-3">
          <button
            onClick={() => reset()}
            className="flex-1 flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white py-3.5 px-6 rounded-2xl font-bold transition-all shadow-lg shadow-indigo-500/30"
          >
            <RefreshCcw size={18} />
            Try Again
          </button>

          <Link
            href="/"
            className="flex-1 flex items-center justify-center gap-2 bg-slate-100 hover:bg-slate-200 dark:bg-slate-800 dark:hover:bg-slate-700 text-slate-700 dark:text-slate-300 py-3.5 px-6 rounded-2xl font-bold transition-all"
          >
            <Home size={18} />
            Go Home
          </Link>
        </div>
      </motion.div>
    </div>
  );
}

