         ) : null}

         {/* SECTION 4 - STANDARD NEARBY QUEUES FEED */}
         {(searchQuery.length > 0 || activeCategory !== "all") && (
            <section>
               <h2 className="text-lg font-black text-white mb-4 px-1">{filteredBusinesses.length} Queues nearby</h2>
