                  Continue with your phone or email
                </p>
              </div>

              <div className="mb-10">
                <GoogleSignInButton 
                  redirectTo={intendedRole === "business_owner" ? "/dashboard" : "/home"} 
                  role={intendedRole || "customer"}
                />
                <div className="relative mt-10 mb-6">
                  <div className="absolute inset-0 flex items-center">
                    <div className="w-full border-t border-white/10"></div>
                  </div>
                  <div className="relative flex justify-center text-[10px] uppercase font-black tracking-widest text-zinc-600 bg-surface px-6">
                    secure OTP access
                  </div>
                </div>
              </div>

              <div className="space-y-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] ml-2">Email Address</label>
                  <input 
                    type="email" 
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    placeholder="name@company.com"
                    className="w-full px-8 py-5 rounded-2xl border-2 border-white/5 bg-black/20 text-white placeholder:text-zinc-700 focus:outline-none focus:border-primary/50 transition-all font-bold text-base"
                    required
                  />
                </div>

                <button 
                  onClick={() => {
                    if (!email || !email.includes('@')) {
                      toast.error("Please enter a valid email");
                      return;
                    }
                    setShowOTP(true);
                  }}
                  className={`w-full py-5 rounded-2xl flex items-center justify-center gap-3 font-black uppercase tracking-widest text-sm transition-all shadow-xl active:scale-95 ${intendedRole === 'business_owner' ? 'bg-primary text-black shadow-primary/20 hover:bg-indigo-400' : 'bg-emerald-500 text-black shadow-emerald-500/20 hover:bg-emerald-400'}`}
                >
                  Send OTP <ArrowRight size={20} strokeWidth={3} />
                </button>
              </div>
            </motion.div>
          )}
        </div>
      </div>

      {showOTP && (
        <EmailOTPModal 
          defaultEmail={email}
          onClose={() => setShowOTP(false)}
          onSuccess={handleAuthSuccess}
        />
      )}
      
      {/* Footer minimal */}
      <footer className="py-8 text-center text-slate-600 text-xs font-medium border-t border-white/5 bg-background">
        ┬⌐ 2026 QueueLess India. Secure {intendedRole === "business_owner" ? "Business" : ""} Authentication.
      </footer>
    </div>
  );
}

"use client";

import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { MapPin, ArrowRight, Clock, Users, Star, Search, Filter } from 'lucide-react';
import Link from 'next/link';
import dynamic from 'next/dynamic';
import { createClient } from '@/lib/supabase/client';

// Dynamically import the Leaflet map to avoid SSR issues
const LeafletMap = dynamic(() => import('@/components/Map/LeafletBusinessMap'), {
  ssr: false,
  loading: () => (
    <div className="w-full h-full bg-slate-950 flex items-center justify-center">
      <div className="w-12 h-12 border-4 border-slate-800 border-t-indigo-500 rounded-full animate-spin" />
    </div>
  ),
});

// Major Indian cities with approximate coordinates
const CITIES = [
  { name: 'All India', lat: 20.5937, lng: 78.9629, zoom: 5 },
  { name: 'Delhi', lat: 28.6139, lng: 77.2090, zoom: 12 },
  { name: 'Mumbai', lat: 19.0760, lng: 72.8777, zoom: 12 },
  { name: 'Bengaluru', lat: 12.9716, lng: 77.5946, zoom: 12 },
  { name: 'Chennai', lat: 13.0827, lng: 80.2707, zoom: 12 },
  { name: 'Hyderabad', lat: 17.3850, lng: 78.4867, zoom: 12 },
  { name: 'Pune', lat: 18.5204, lng: 73.8567, zoom: 12 },
  { name: 'Kolkata', lat: 22.5726, lng: 88.3639, zoom: 12 },
  { name: 'Ahmedabad', lat: 23.0225, lng: 72.5714, zoom: 12 },
];

const CATEGORIES = ['all', 'hospitals', 'banks', 'salons', 'restaurants', 'government'];

export interface MapBusiness {
  id: string;
  name: string;
  category: string;
  location: string;
  avg_rating: number;
  total_reviews: number;
  lat?: number;
  lng?: number;
  totalWaiting: number;
  isActive: boolean;
  estimatedWait: number;
}

export default function CityQueueMap() {
  const supabase = createClient();
  const [businesses, setBusinesses] = useState<MapBusiness[]>([]);
  const [activeCity, setActiveCity] = useState(CITIES[0]);
  const [activeCategory, setActiveCategory] = useState('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedBusiness, setSelectedBusiness] = useState<MapBusiness | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchBusinesses();
  }, []);

  const fetchBusinesses = async () => {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('businesses')
        .select(`
          *,
          queues!queues_org_id_fkey (
            total_waiting,
            is_active,
            is_accepting_tokens,
            last_issued_number
          )
        `)
        .order('avg_rating', { ascending: false });

      if (error) throw error;

      const mapped: MapBusiness[] = (data || []).map((biz: any) => {
        const queue = biz.queues?.[0];
        return {
          id: biz.id,
          name: biz.name,
          category: biz.category || 'other',
          location: biz.location || '',
          avg_rating: biz.avg_rating || 0,
          total_reviews: biz.total_reviews || 0,
          lat: biz.lat,
          lng: biz.lng,
          totalWaiting: queue?.total_waiting || 0,
          isActive: queue?.is_active || false,
          estimatedWait: (queue?.total_waiting || 0) * (biz.serviceMins || 5),
        };
      });

      setBusinesses(mapped);
    } catch (err) {
      console.error('Failed to fetch businesses:', err);
    } finally {
      setLoading(false);
    }
  };

  const filteredBusinesses = businesses.filter((b) => {
    if (activeCategory !== 'all' && !b.category.toLowerCase().includes(activeCategory.replace('s', ''))) return false;
    if (searchQuery && !b.name.toLowerCase().includes(searchQuery.toLowerCase()) && !b.location.toLowerCase().includes(searchQuery.toLowerCase())) return false;
    return true;
  });

  return (
    <div className="relative w-full h-screen bg-[#0a0a0a] overflow-hidden font-sans">
      {/* Map */}
      <div className="absolute inset-0">
        <LeafletMap
          businesses={filteredBusinesses}
          center={[activeCity.lat, activeCity.lng]}
          zoom={activeCity.zoom}
          onSelect={setSelectedBusiness}
        />
      </div>

      {/* Top Bar */}
      <header className="absolute top-0 inset-x-0 z-[500] p-4 pointer-events-none">
        <div className="max-w-7xl mx-auto flex flex-col gap-3 pointer-events-auto">
          {/* Search + Back */}
          <div className="flex items-center gap-3">
            <Link
              href="/customer"
              className="flex items-center gap-2 bg-white/90 dark:bg-black/60 bg-opacity-95 border border-white/10 px-4 py-2.5 rounded-full text-white shadow-lg hover:bg-white/10 transition shrink-0"
            >
              <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
              <span className="font-bold text-sm">Live Map</span>
            </Link>
            <div className="relative flex-1 max-w-md">
              <Search size={16} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
              <input
                type="text"
                placeholder="Search businesses..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-10 pr-4 py-2.5 bg-black/60 bg-opacity-95 border border-white/10 rounded-full text-white text-sm placeholder:text-slate-500 focus:outline-none focus:border-indigo-500"
              />
            </div>
          </div>

          {/* City Quick Filters */}
          <div className="flex items-center gap-2 overflow-x-auto scrollbar-hide pb-1">
            {CITIES.map((city) => (
              <button
                key={city.name}
                onClick={() => setActiveCity(city)}
                className={`px-4 py-1.5 rounded-full text-xs font-bold uppercase tracking-wider whitespace-nowrap transition-all ${
                  activeCity.name === city.name
                    ? 'bg-indigo-600 text-white shadow-lg'
                    : 'bg-black/40 bg-opacity-95 text-slate-400 border border-white/10 hover:text-white'
                }`}
              >
                {city.name}
              </button>
            ))}
          </div>

          {/* Category Filters */}
          <div className="hidden md:flex items-center gap-2">
            {CATEGORIES.map((f) => (
              <button
                key={f}
                onClick={() => setActiveCategory(f)}
                className={`px-4 py-1.5 rounded-full text-xs font-bold uppercase tracking-wider transition-all ${
                  activeCategory === f
                    ? 'bg-emerald-600 text-white shadow-md'
                    : 'bg-black/40 bg-opacity-95 text-slate-500 border border-white/10 hover:text-white'
                }`}
              >
                {f}
              </button>
            ))}
          </div>
        </div>
      </header>

      {/* Wait Time Legend */}
      <div className="absolute top-44 md:top-36 right-4 z-[500] hidden md:block">
        <div className="bg-black/60 bg-opacity-95 border border-white/10 rounded-2xl p-4 w-44">
          <h4 className="text-white text-[10px] font-black uppercase tracking-widest mb-3">Wait Time</h4>
          <div className="space-y-2 text-xs font-medium text-slate-300">
            <div className="flex items-center justify-between">
              <span className="flex items-center gap-2"><span className="w-3 h-3 rounded-full bg-emerald-500" /> Green</span>&lt; 15m
            </div>
            <div className="flex items-center justify-between">
              <span className="flex items-center gap-2"><span className="w-3 h-3 rounded-full bg-amber-400" /> Yellow</span> 15-30m
            </div>
            <div className="flex items-center justify-between">
              <span className="flex items-center gap-2"><span className="w-3 h-3 rounded-full bg-rose-500" /> Red</span>&gt; 30m
            </div>
          </div>
        </div>
      </div>

      {/* Selected Business Panel */}
      {selectedBusiness && (
        <motion.div
          initial={{ y: 100, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          className="absolute bottom-6 left-4 right-4 md:left-auto md:right-6 md:w-80 z-[500]"
        >
          <div className="bg-black/80 bg-opacity-95 border border-white/10 rounded-3xl p-5 shadow-2xl">
            <div className="flex items-start justify-between mb-3">
              <div>
                <h3 className="text-white font-black text-lg">{selectedBusiness.name}</h3>
                <p className="text-slate-400 text-xs">{selectedBusiness.location}</p>
              </div>
              <button onClick={() => setSelectedBusiness(null)} className="text-slate-500 hover:text-white p-1">Γ£ò</button>
            </div>
            <div className="flex items-center gap-4 mb-4">
              <div className="flex items-center gap-1 text-amber-400 text-xs font-bold">
                <Star size={12} fill="currentColor" /> {selectedBusiness.avg_rating.toFixed(1)}
              </div>
              <div className="flex items-center gap-1 text-blue-400 text-xs font-bold">
                <Users size={12} /> {selectedBusiness.totalWaiting} waiting
              </div>
              <div className="flex items-center gap-1 text-slate-400 text-xs font-bold">
                <Clock size={12} /> ~{selectedBusiness.estimatedWait}m
              </div>
            </div>
            <Link
              href={`/b/${selectedBusiness.id}`}
              className="block w-full py-3 rounded-xl bg-[#00F5A0] text-black font-black text-center text-sm hover:brightness-110 transition"
            >
              Join Queue <ArrowRight size={14} className="inline ml-1" />
            </Link>
          </div>
        </motion.div>
      )}

      {/* Results Count */}
      <div className="absolute bottom-6 left-4 z-[500] md:hidden">
        <div className="bg-black/60 bg-opacity-95 border border-white/10 rounded-full px-4 py-2 text-xs text-slate-300 font-bold">
          {filteredBusinesses.length} businesses found
        </div>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { createClient } from "@/lib/supabase/client";
import { useAuth } from "@/context/AuthContext";

const supabase = createClient();
import { motion, AnimatePresence } from "framer-motion";
import { ChevronLeft, Ticket, Clock, Building2, CheckCircle, Loader } from "lucide-react";

type TabType = "active" | "past";

interface TokenRecord {
  id: string;
  tokenNumber: string;
  orgId: string;
  status: string;
  createdAt: string;
  estimatedWaitMins: number;
  businessName?: string;
}

export default function MyTokensPage() {
  const router = useRouter();
  const { user, isAuthenticated, loading } = useAuth();
  const [activeTab, setActiveTab] = useState<TabType>("active");
  const [activeTokens, setActiveTokens] = useState<TokenRecord[]>([]);
  const [pastTokens, setPastTokens] = useState<TokenRecord[]>([]);
  const [fetchingTokens, setFetchingTokens] = useState(true);

  useEffect(() => {
    if (loading) return;

    const handleSync = () => {
      if (isAuthenticated) {
        fetchTokens();
      } else {
        fetchGuestTokens();
      }
    };

    handleSync();

    window.addEventListener('online', handleSync);
    return () => window.removeEventListener('online', handleSync);
  }, [user, isAuthenticated, loading]);

  const fetchGuestTokens = () => {
    setFetchingTokens(true);
    try {
      const guestSession = localStorage.getItem('queueless_guest_session');
      if (guestSession) {
        const session = JSON.parse(guestSession);
        if (session.activeTokenId) {
          const guestToken: TokenRecord = {
            id: session.activeTokenId,
            tokenNumber: session.activeTokenNumber,
            orgId: session.orgId || 'unknown',
            status: 'WAITING',
            createdAt: new Date().toISOString(),
            estimatedWaitMins: 5,
            businessName: session.businessName || 'Your Queue'
          };
          setActiveTokens([guestToken]);
        }
      }
    } catch (e) {
      console.error("Guest fetch error", e);
    } finally {
      setFetchingTokens(false);
    }
  };

  const fetchTokens = async () => {
    if (!user) return;
    setFetchingTokens(true);
    try {
      // Try cache first if offline
      if (!navigator.onLine) {
        const cached = localStorage.getItem(`tokens_cache_${user.id}`);
        if (cached) {
          const { active, past } = JSON.parse(cached);
          setActiveTokens(active);
          setPastTokens(past);
          setFetchingTokens(false);
          return;
        }
      }

      const { data: tokens, error } = await supabase
        .from("tokens")
        .select("*")
        .eq("userId", user.id)
        .order("createdAt", { ascending: false })
        .limit(50);

      if (error) throw error;

      const enriched: TokenRecord[] = await Promise.all(
        (tokens || []).map(async (t: any) => {
          const { data: biz } = await supabase
            .from("businesses")
            .select("name")
            .eq("id", t.orgId)
            .maybeSingle();
          return { ...t, businessName: biz?.name || t.orgId };
        })
      );

      const active = enriched.filter(t => ["WAITING", "SERVING"].includes(t.status));
      const past = enriched.filter(t => ["SERVED", "CANCELLED"].includes(t.status));

      setActiveTokens(active);
      setPastTokens(past);

      // Cache for offline
      localStorage.setItem(`tokens_cache_${user.id}`, JSON.stringify({ active, past }));
    } catch (err) {
      console.error("Error fetching tokens:", err);
    } finally {
      setFetchingTokens(false);
    }
  };

  const formatDate = (dateStr: string) => {
    const d = new Date(dateStr);
    return d.toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "numeric" });
  };

  const statusConfig: Record<string, { label: string; color: string; dot: string }> = {
    WAITING: { label: "Waiting", color: "text-amber-400 bg-amber-500/10 border-amber-500/20", dot: "bg-amber-400 animate-pulse" },
    SERVING: { label: "Serving Now", color: "text-emerald-400 bg-emerald-500/10 border-emerald-500/20", dot: "bg-emerald-400 animate-pulse" },
    SERVED: { label: "Completed", color: "text-slate-400 bg-white/5 border-white/10", dot: "bg-slate-500" },
    CANCELLED: { label: "Cancelled", color: "text-rose-400 bg-rose-500/10 border-rose-500/20", dot: "bg-rose-500" },
  };

  const TokenCard = ({ token }: { token: TokenRecord }) => {
    const cfg = statusConfig[token.status] || statusConfig.WAITING;
    const isActive = ["WAITING", "SERVING"].includes(token.status);
    return (
      <motion.div
        initial={{ opacity: 0, y: 8 }}
        animate={{ opacity: 1, y: 0 }}
        onClick={() => isActive && router.push(`/track/${token.tokenNumber}`)}
        className={`bg-[#111118] border border-white/5 rounded-2xl p-5 flex items-center gap-4 transition-all ${isActive ? "hover:border-[#00F5A0]/30 hover:bg-[#111118]/80 cursor-pointer active:scale-[0.98]" : ""}`}
      >
        {/* Token Icon */}
        <div className="w-12 h-12 rounded-xl bg-primary/10 border border-[#00F5A0]/20 flex flex-col items-center justify-center flex-shrink-0">
          <span className="text-[9px] font-black text-primary uppercase tracking-wide leading-none">{token.tokenNumber.split("-")[0]}</span>
          <span className="text-lg font-black text-white leading-tight">{token.tokenNumber.split("-")[1] || token.tokenNumber}</span>
        </div>

        {/* Info */}
        <div className="flex-1 min-w-0">
          <p className="text-white font-bold text-sm truncate">{token.businessName}</p>
          <div className="flex items-center gap-2 mt-1">
            <div className={`flex items-center gap-1.5 px-2 py-0.5 rounded-full text-[10px] font-bold border ${cfg.color}`}>
              <span className={`w-1.5 h-1.5 rounded-full ${cfg.dot}`}></span>
              {cfg.label}
            </div>
          </div>
          <p className="text-slate-500 text-[11px] font-medium mt-1 flex items-center gap-1">
            <Clock size={10} /> {formatDate(token.createdAt)}
          </p>
        </div>

        {/* Arrow or Checkmark */}
        {isActive ? (
          <div className="text-indigo-400 flex-shrink-0">
            <ChevronLeft size={18} className="rotate-180" />
          </div>
        ) : token.status === "SERVED" ? (
          <CheckCircle size={18} className="text-emerald-500 flex-shrink-0" />
        ) : null}
      </motion.div>
    );
  };

  return (
    <div className="min-h-screen bg-background text-white font-sans">
      {/* Background */}
      <div className="fixed top-0 inset-x-0 h-[40vh] bg-gradient-to-b from-[#00F5A0]/10 via-transparent to-transparent pointer-events-none" />

      <main className="relative z-10 max-w-lg mx-auto px-5 pt-12 pb-24">
        {/* Header */}
        <div className="flex items-center gap-4 mb-10">
          <button onClick={() => router.back()} className="w-10 h-10 rounded-full bg-white/5 border border-white/10 flex items-center justify-center hover:bg-white/10 transition-colors flex-shrink-0">
            <ChevronLeft size={20} className="text-white" />
          </button>
          <div>
            <h1 className="text-2xl font-black tracking-tighter text-white">My Tokens</h1>
            <p className="text-slate-400 text-sm font-medium">Your queue history</p>
          </div>
        </div>

        {/* Tabs */}
        <div className="flex bg-[#111118] border border-white/5 rounded-2xl p-1.5 mb-8">
          {(["active", "past"] as TabType[]).map(tab => (
            <button
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`flex-1 py-2.5 text-sm font-bold rounded-xl transition-all ${activeTab === tab ? "bg-primary text-[#0A0A0F] shadow-lg shadow-primary/20" : "text-slate-400 hover:text-white"}`}
            >
              {tab === "active" ? `Active${activeTokens.length > 0 ? ` (${activeTokens.length})` : ""}` : "Past"}
            </button>
          ))}
        </div>

        {/* Content */}
        {fetchingTokens ? (
          <div className="flex justify-center py-20">
            <Loader size={28} className="animate-spin text-indigo-400" />
          </div>
        ) : (
          <AnimatePresence mode="wait">
            {activeTab === "active" && (
              <motion.div key="active" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
                {activeTokens.length === 0 ? (
                  <div className="text-center py-20">
                    <div className="w-16 h-16 bg-white/5 rounded-2xl flex items-center justify-center mx-auto mb-4">
                      <Ticket size={28} className="text-slate-600" />
                    </div>
                    <p className="text-slate-400 font-medium">No active tokens</p>
                    <p className="text-slate-600 text-sm mt-1">Join a queue at a nearby business!</p>
                    <button
                      onClick={() => router.push("/home")}
                      className="mt-6 px-6 py-3 bg-indigo-600 text-white font-bold rounded-full text-sm hover:bg-indigo-500 transition-colors"
                    >
                      Browse Businesses
                    </button>
                  </div>
                ) : (
                  <div className="flex flex-col gap-3">
                    {activeTokens.map(t => <TokenCard key={t.id} token={t} />)}
                  </div>
                )}
              </motion.div>
            )}

            {activeTab === "past" && (
              <motion.div key="past" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
                {pastTokens.length === 0 ? (
                  <div className="text-center py-20">
                    <div className="w-16 h-16 bg-white/5 rounded-2xl flex items-center justify-center mx-auto mb-4">
                      <Building2 size={28} className="text-slate-600" />
                    </div>
                    <p className="text-slate-400 font-medium">No past visits yet</p>
                    <p className="text-slate-600 text-sm mt-1">Your completed tokens will appear here</p>
                  </div>
                ) : (
                  <div className="flex flex-col gap-3">
                    {pastTokens.slice(0, 20).map(t => <TokenCard key={t.id} token={t} />)}
                  </div>
                )}
              </motion.div>
            )}
          </AnimatePresence>
        )}
      </main>
    </div>
  );
}

