}

'use client';

import { useState, useMemo } from 'react';
import { Calendar, Clock, AlertCircle, Check } from 'lucide-react';
import { createClient } from '@/lib/supabase/client';
import { toast } from 'sonner';

const INDIAN_HOLIDAYS_2026 = [
  '2026-01-26', // Republic Day
  '2026-03-17', // Holi
  '2026-04-14', // Ambedkar Jayanti
  '2026-08-15', // Independence Day
  '2026-10-02', // Gandhi Jayanti
  '2026-10-23', // Diwali
  '2026-11-15', // Guru Nanak Jayanti
  '2026-12-25', // Christmas
];

interface Props {
  businessId: string;
  businessName: string;
  opHours?: string;    // e.g., "09:00-17:00"
  opHoursJson?: Record<string, { open: string; close: string }[] | null>;
  serviceMins?: number;
  closedDays?: number[]; // 0=Sun, 6=Sat
}

export default function AdvanceBookingForm({
  businessId,
  businessName,
  opHours = "09:00-17:00",
  opHoursJson,
  serviceMins = 15,
  closedDays = [0], // Sunday closed by default
}: Props) {
  const supabase = createClient();
  const [selectedDate, setSelectedDate] = useState("");
  const [selectedSlot, setSelectedSlot] = useState("");
  const [customerName, setCustomerName] = useState("");
  const [customerPhone, setCustomerPhone] = useState("");
  const [loading, setLoading] = useState(false);
  const [booked, setBooked] = useState(false);

  // Parse operating hours into slot list
  const slots = useMemo(() => {
    if (!selectedDate) return [];

    const date = new Date(selectedDate);
    const dayNames = ["sun", "mon", "tue", "wed", "thu", "fri", "sat"];
    const dayKey = dayNames[date.getDay()];

    const daySlots = opHoursJson?.[dayKey];

    if (daySlots && daySlots.length > 0) {
      const result: string[] = [];
      daySlots.forEach((shift) => {
        const [startH, startM] = shift.open.split(":").map(Number);
        const [endH, endM] = shift.close.split(":").map(Number);
        let current = startH * 60 + startM;
        const end = endH * 60 + endM;

        while (current + serviceMins <= end) {
          const h = Math.floor(current / 60);
          const m = current % 60;
          result.push(
            `${h.toString().padStart(2, "0")}:${m.toString().padStart(2, "0")}`,
          );
          current += serviceMins;
        }
      });
      return result;
    }

    // Fallback to legacy opHours text parsing
    // predictions.id = businesses.id (slug)
    const [startStr, endStr] = opHours.split("-");
    const [startH, startM] = startStr.split(":").map(Number);
    const [endH, endM] = endStr.split(":").map(Number);

    const result: string[] = [];
    let current = startH * 60 + startM;
    const end = endH * 60 + endM;

    while (current + serviceMins <= end) {
      const h = Math.floor(current / 60);
      const m = current % 60;
      result.push(
        `${h.toString().padStart(2, "0")}:${m.toString().padStart(2, "0")}`,
      );
      current += serviceMins;
    }
    return result;
  }, [selectedDate, opHours, opHoursJson, serviceMins]);

  const isDateBlocked = (dateStr: string): boolean => {
    const date = new Date(dateStr);
    const dayOfWeek = date.getDay();
    const dayNames = ["sun", "mon", "tue", "wed", "thu", "fri", "sat"];
    const dayKey = dayNames[dayOfWeek];

    // Check JSON hours first
    if (opHoursJson) {
      if (opHoursJson[dayKey] === null) return true;
      if (opHoursJson[dayKey] !== undefined) return false; // If explicitly set to something non-null, it's open
    }

    // Fallback to legacy closedDays
    if (closedDays.includes(dayOfWeek)) return true;
    if (INDIAN_HOLIDAYS_2026.includes(dateStr)) return true;
    return false;
  };

  const isHoliday = (dateStr: string): string | null => {
    const holidays: Record<string, string> = {
      '2026-01-26': 'Republic Day',
      '2026-03-17': 'Holi',
      '2026-04-14': 'Ambedkar Jayanti',
      '2026-08-15': 'Independence Day',
      '2026-10-02': 'Gandhi Jayanti',
      '2026-10-23': 'Diwali',
      '2026-11-15': 'Guru Nanak Jayanti',
      '2026-12-25': 'Christmas',
    };
    return holidays[dateStr] || null;
  };

  const handleBook = async () => {
    const normalizePhone = (p: string) => {
      let cleaned = p.replace(/\D/g, "");
      if (cleaned.startsWith("91") && cleaned.length === 12) {
        cleaned = cleaned.substring(2);
      } else if (cleaned.startsWith("0") && cleaned.length === 11) {
        cleaned = cleaned.substring(1);
      }
      return cleaned;
    };

    const digits = normalizePhone(customerPhone);

    if (!selectedDate || !selectedSlot || !customerName) {
      toast.error('Please fill all fields');
      return;
    }

    if (!/^[6-9]\d{9}$/.test(digits)) {
      toast.error("Please enter a valid 10-digit Indian mobile number");
      return;
    }

    setLoading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();

      const { error } = await supabase.from('advance_bookings').insert({
        business_id: businessId,
        user_id: user?.id || null,
        customer_name: customerName,
        customer_phone: "+91" + digits,
        booking_date: selectedDate,
        booking_time: selectedSlot,
        status: 'confirmed',
      });

      if (error) throw error;

      setBooked(true);
      toast.success('Booking confirmed!');
    } catch (err: any) {
      console.error(err);
      toast.error(err.message || 'Booking failed');
    } finally {
      setLoading(false);
    }
  };

  if (booked) {
    return (
      <div className="bg-white dark:bg-slate-900 rounded-3xl p-8 border border-slate-200 dark:border-slate-800 text-center">
        <div className="w-16 h-16 rounded-full bg-emerald-500/10 flex items-center justify-center mx-auto mb-4">
          <Check size={32} className="text-emerald-500" />
        </div>
        <h3 className="text-xl font-black text-slate-900 dark:text-white mb-2">Booking Confirmed!</h3>
        <p className="text-slate-500 text-sm mb-1">{businessName}</p>
        <p className="text-slate-400 text-sm">{selectedDate} at {selectedSlot}</p>
        <p className="text-slate-400 text-xs mt-4">You'll receive a confirmation at your registered contact.</p>
      </div>
    );
  }

  const today = new Date().toISOString().split('T')[0];
  const maxDate = new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
  const holidayName = selectedDate ? isHoliday(selectedDate) : null;

  return (
    <div className="bg-white dark:bg-slate-900 rounded-3xl p-6 border border-slate-200 dark:border-slate-800">
      <div className="flex items-center gap-2 mb-6">
        <Calendar size={20} className="text-indigo-500" />
        <h3 className="text-lg font-black text-slate-900 dark:text-white">Advance Booking</h3>
      </div>

      <div className="space-y-4">
        {/* Customer Name */}
        <input
          type="text"
          placeholder="Your Name"
          value={customerName}
          onChange={(e) => setCustomerName(e.target.value)}
          className="w-full px-4 py-3 bg-slate-50 dark:bg-white/5 border border-slate-200 dark:border-white/10 rounded-xl text-slate-900 dark:text-white placeholder:text-slate-400 focus:outline-none focus:border-indigo-500 text-sm"
        />

        {/* Phone */}
        <input
          type="tel"
          placeholder="WhatsApp Number (optional)"
          value={customerPhone}
          onChange={(e) => setCustomerPhone(e.target.value)}
          className="w-full px-4 py-3 bg-slate-50 dark:bg-white/5 border border-slate-200 dark:border-white/10 rounded-xl text-slate-900 dark:text-white placeholder:text-slate-400 focus:outline-none focus:border-indigo-500 text-sm"
        />

        {/* Date Picker */}
        <div>
          <label className="text-[10px] font-bold uppercase tracking-widest text-slate-400 mb-1 block">Select Date</label>
          <input
            type="date"
            min={today}
            max={maxDate}
            value={selectedDate}
            onChange={(e) => {
              const val = e.target.value;
              if (isDateBlocked(val)) {
                toast.error(isHoliday(val) ? `Closed: ${isHoliday(val)}` : 'Closed on this day');
                return;
              }
              setSelectedDate(val);
              setSelectedSlot('');
            }}
            className="w-full px-4 py-3 bg-slate-50 dark:bg-white/5 border border-slate-200 dark:border-white/10 rounded-xl text-slate-900 dark:text-white focus:outline-none focus:border-indigo-500 text-sm"
          />
          {holidayName && (
            <p className="text-amber-500 text-xs font-bold mt-1 flex items-center gap-1">
              <AlertCircle size={12} /> {holidayName} ΓÇö Closed
            </p>
          )}
        </div>

        {/* Time Slots */}
        {selectedDate && !isDateBlocked(selectedDate) && (
          <div>
            <label className="text-[10px] font-bold uppercase tracking-widest text-slate-400 mb-2 block">
              <Clock size={12} className="inline mr-1" /> Available Slots
            </label>
            <div className="grid grid-cols-4 gap-2 max-h-40 overflow-y-auto">
              {slots.map((slot) => (
                <button
                  key={slot}
                  onClick={() => setSelectedSlot(slot)}
                  className={`py-2 rounded-lg text-xs font-bold transition-all ${
                    selectedSlot === slot
                      ? 'bg-indigo-600 text-white shadow-md'
                      : 'bg-slate-100 dark:bg-white/5 text-slate-600 dark:text-slate-300 hover:bg-indigo-100 dark:hover:bg-indigo-500/10'
                  }`}
                >
                  {slot}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* Book Button */}
        <button
          onClick={handleBook}
          disabled={loading || !selectedDate || !selectedSlot || !customerName}
          className="w-full py-3 rounded-xl bg-indigo-600 text-white font-black text-sm hover:bg-indigo-700 transition disabled:opacity-50 disabled:cursor-not-allowed"
        >
          {loading ? 'Booking...' : 'Confirm Booking'}
        </button>
      </div>
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { 
  Users, Clock, Zap, TrendingUp, TrendingDown, 
  ArrowLeft, Download, Calendar, Info, BrainCircuit, Lock
} from 'lucide-react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, 
  ResponsiveContainer, LineChart, Line, ReferenceLine, 
  PieChart, Pie, Cell, AreaChart, Area
} from 'recharts';
import { format, subDays } from 'date-fns';
import { createClient } from '@/lib/supabase/client';
import { FEATURES } from '@/lib/features';
import Link from 'next/link';
import GlassCard from '@/components/ui/GlassCard';
import CountUp from '@/components/ui/CountUp';
import { jsPDF } from 'jspdf';
import { toast } from 'sonner';

// --- MOCK DATA FOR UI PREVIEW ---
const MOCK_HOURLY = Array.from({ length: 15 }, (_, i) => ({
  hour: `${i + 6}:00`,
  count: Math.floor(Math.random() * 20) + 5,
  isPeak: (i + 6) >= 10 && (i + 6) <= 12
}));

const MOCK_LINE = Array.from({ length: 7 }, (_, i) => ({
  day: format(subDays(new Date(), 6 - i), 'EEE'),
  wait: Math.floor(Math.random() * 15) + 10
}));

const MOCK_PIE = [
  { name: 'Returning', value: 36, color: '#00F5A0' },
  { name: 'First-time', value: 64, color: 'rgba(255,255,255,0.1)' }
];

export default function AnalyticsDashboard({ businessId }: { businessId: string }) {
  const supabase = createClient();
  const [isLoading, setIsLoading] = useState(true);
  const [insights, setInsights] = useState<string[]>([]);
  const [hourlyData, setHourlyData] = useState<any[]>(MOCK_HOURLY);
  const [dailyStats, setDailyStats] = useState<any[]>(MOCK_LINE);
  const [isLocked, setIsLocked] = useState(false);
  const [summaryStats, setSummaryStats] = useState({ totalServed: 0, avgWait: 0, noShowRate: 0, completionRate: 0 });

  useEffect(() => {
    if (!businessId) return;

    const fetchData = async () => {
      try {
        // 1. Check Subscription Gate (bypassed during testing phase)
        if (!FEATURES.IS_TESTING_PHASE) {
          const { data: biz } = await supabase.from('businesses').select('plan').eq('id', businessId).single();
          if (biz?.plan === 'free') {
             setIsLocked(true);
             setIsLoading(false);
             return;
          }
        }

        // 1b. Fetch real metrics from daily_stats (last 7 days)
        const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
        const { data: statsRows } = await supabase
          .from('daily_stats')
          .select('*')
          .eq('business_id', businessId)
          .gte('stat_date', sevenDaysAgo)
          .order('stat_date', { ascending: true });

        if (statsRows && statsRows.length > 0) {
          const totalServed = statsRows.reduce((sum: number, s: any) => sum + (s.total_served || 0), 0);
          const avgWait = Math.round(statsRows.reduce((sum: number, s: any) => sum + (s.avg_wait_mins || 0), 0) / statsRows.length);
          const totalIssued = statsRows.reduce((sum: number, s: any) => sum + (s.total_tokens_issued || 0), 0);
          const totalNoShows = statsRows.reduce((sum: number, s: any) => sum + (s.total_no_shows || 0), 0);
          const noShowRate = totalIssued > 0 ? Math.round((totalNoShows / totalIssued) * 100) : 0;
          const completionRate = totalIssued > 0 ? Math.round((totalServed / totalIssued) * 100) : 0;

          setSummaryStats({ totalServed, avgWait, noShowRate, completionRate });

          // Update daily trend chart from real data
          setDailyStats(statsRows.map((d: any) => ({
            day: format(new Date(d.stat_date), 'EEE'),
            wait: d.avg_wait_mins || 0
          })));
        }

        // 2. Fetch Hourly Data
        const today = new Date().toISOString().split('T')[0];
        const { data: hourly } = await supabase.rpc('get_hourly_distribution', { 
          org_id_param: businessId, 
          date_param: today 
        });

        if (hourly) {
          const formattedHourly = Array.from({ length: 15 }, (_, i) => {
             const h = i + 6;
             const found = hourly.find((d: any) => d.hour_val === h);
             return {
               hour: `${h}:00`,
               count: found ? found.token_count : 0,
               isPeak: h >= 10 && h <= 12
             };
          });
          setHourlyData(formattedHourly);
        }

        // 3. Fetch Wait Time Trend (Last 7 Days)
        const { data: trend } = await supabase.rpc('get_wait_time_trend', {
          org_id_param: businessId,
          days_param: 7
        });
        if (trend) {
           setDailyStats(trend.map((d: any) => ({
             day: format(new Date(d.date_val), 'EEE'),
             wait: d.avg_wait
           })));
        }

        // 4. AI Insights via Edge Function
        const { data: aiResponse } = await supabase.functions.invoke('predict-queue', {
          body: { orgId: businessId, stats: { currentlyWaiting: 5, totalToday: 47 } }
        });

        if (aiResponse && aiResponse.strategies) {
          setInsights(aiResponse.strategies);
        } else {
          setInsights([
            "≡ƒôê Tuesdays are 40% busier than average. Consider adding staff.",
            "ΓÜí Fast Pass adoption is low (3%). Try reducing price to Γé╣49.",
            "≡ƒÄ» Your service time improved by 2 mins this week. Great work!"
          ]);
        }

      } catch (err) {
        console.error("Fetch failed", err);
      } finally {
        setIsLoading(false);
      }
    };

    fetchData();
  }, [businessId]);

  const handleExport = () => {
    const doc = new jsPDF();

    // Header
    doc.setFillColor(10, 10, 15);
    doc.rect(0, 0, 210, 40, 'F');

    doc.setTextColor(255, 255, 255);
    doc.setFontSize(24);
    doc.setFont("helvetica", "bold");
    doc.text("QueueLess India", 20, 20);

    doc.setFontSize(10);
    doc.text("PERFORMANCE INTELLIGENCE REPORT", 20, 28);

    doc.setTextColor(150, 150, 150);
    doc.text(`Business ID: ${businessId}`, 190, 28, { align: 'right' });

    // Grid Lines & Content
    doc.setDrawColor(230, 230, 230);
    doc.line(20, 45, 190, 45);

    doc.setTextColor(0, 0, 0);
    doc.setFontSize(14);
    doc.text("Daily Snapshot", 20, 55);

    const stats = [
      ["Metric", "Value", "Daily Trend"],
      ["Total Tokens", "47", "+12%"],
      ["Avg Wait Time", "18 mins", "-3 mins"],
      ["Peak Hour", "11:00 AM", "Stable"],
      ["Completion Rate", "94%", "+2%"]
    ];

    let y = 65;
    stats.forEach((row, i) => {
      doc.setFont("helvetica", i === 0 ? "bold" : "normal");
      doc.text(row[0], 25, y);
      doc.text(row[1], 80, y);
      doc.text(row[2], 130, y);
      y += 10;
    });

    // Insights Section
    y += 10;
    doc.setFillColor(240, 255, 250);
    doc.rect(20, y, 170, 45, 'F');

    doc.setTextColor(0, 100, 80);
    doc.setFont("helvetica", "bold");
    doc.text("AI SERVICE RECOMMENDATIONS", 25, y + 10);

    doc.setFont("helvetica", "normal");
    doc.setTextColor(50, 50, 50);
    doc.setFontSize(10);
    insights.forEach((insight, idx) => {
      doc.text(`ΓÇó ${insight}`, 30, y + 20 + (idx * 7));
    });

    doc.save(`QueueLess_Report_${businessId}.pdf`);
    toast.success("Report downloaded successfully");
  };

  if (isLocked) {
    return (
      <div className="flex flex-col items-center justify-center py-20 text-center">
        <div className="w-20 h-20 rounded-full bg-amber-500/10 flex items-center justify-center text-amber-500 mb-8">
          <Zap size={40} fill="currentColor" />
        </div>
        <h2 className="text-3xl font-black text-white mb-4 tracking-tight">Growth Plan Required</h2>
        <p className="text-slate-400 mb-8 max-w-md mx-auto leading-relaxed">
          Unlock business intelligence, AI insights, and professional PDF reports to optimize your queue and increase revenue.
        </p>
        <button 
          className="px-8 py-4 rounded-xl bg-[#00F5A0] text-black font-black uppercase text-xs tracking-widest hover:brightness-110 transition-all shadow-[0_0_20px_rgba(0,245,160,0.3)]"
          onClick={() => { /* Trigger Upgrade Modal in parent if needed */ }}
        >
          Upgrade for Γé╣2,499/mo
        </button>
      </div>
    );
  }

  if (isLoading) {
    return (
      <div className="py-32 flex flex-col items-center gap-4">
        <div className="w-12 h-12 border-4 border-[#00F5A0]/20 border-t-[#00F5A0] rounded-full animate-spin" />
        <p className="text-[#00F5A0] font-black uppercase tracking-widest text-xs">Syncing Analytics...</p>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">

      {/* Stats Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-white tracking-tight">Business Intelligence</h2>
          <p className="text-slate-500 mt-1 font-medium">Real-time performance metrics for {businessId}</p>
        </div>
        <button 
          onClick={handleExport}
          className="flex items-center gap-2 px-6 py-4 rounded-2xl bg-white/5 border border-white/10 text-white font-black uppercase text-xs hover:bg-white hover:text-black transition-all active:scale-95"
        >
          <Download size={18} /> Export PDF Report
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">

        {/* SNAPSHOTS */}
        <div className="lg:col-span-8 grid grid-cols-1 sm:grid-cols-2 gap-4">
           {[
             { label: "Customers Served", value: `${summaryStats.totalServed}`, delta: "7d", color: "#00F5A0", icon: Users },
             { label: "Avg Wait Time", value: `${summaryStats.avgWait}m`, delta: "avg", color: "#38BDF8", icon: Clock },
             { label: "No-Show Rate", value: `${summaryStats.noShowRate}%`, delta: "7d", color: "#FBBF24", icon: Zap },
             { label: "Completion", value: `${summaryStats.completionRate}%`, delta: "7d", color: "#A78BFA", icon: TrendingUp }
           ].map((stat, i) => (
             <OverviewCard key={i} {...stat} />
           ))}
        </div>

        {/* AI PANEL */}
        <div className="lg:col-span-4">
          <GlassCard className="h-full bg-gradient-to-br from-[#00F5A0]/5 to-transparent border-[#00F5A0]/10">
            <div className="flex items-center gap-2 mb-6">
              <BrainCircuit className="text-[#00F5A0]" size={20} />
              <h3 className="text-sm font-black text-white uppercase tracking-widest">AI Insights</h3>
            </div>
            <div className="space-y-3">
              {insights.map((insight, idx) => (
                <motion.div 
                  initial={{ opacity: 0, x: 20 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: idx * 0.1 }}
                  key={idx} 
                  className="p-4 rounded-xl bg-white/[0.03] border border-white/5 text-[13px] font-medium text-slate-300 leading-relaxed"
                >
                  {insight}
