              <div>
                <h3 className="text-xl font-black text-white tracking-tight">Hourly Traffic</h3>
                <p className="text-[10px] text-slate-500 font-bold mt-1 uppercase tracking-widest">Peak Period: 10:00 AM - 12:00 PM</p>
