"use client";

import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  Line,
  Legend
} from "recharts";
import { useEffect, useState } from "react";

// In a real app, this data would be derived from the Firestore `servedAt` timestamps
// For the UI demonstration, we generate realistic looking hourly traffic data.
const generateMockTrafficData = () => {
  const data = [];
  const startHour = 8; // 8 AM
  for (let i = 0; i < 10; i++) {
    const hour = startHour + i;
    const timeStr = hour > 12 ? `${hour - 12} PM` : `${hour} AM`;
    data.push({
      time: timeStr,
      customers: Math.floor(Math.random() * 40) + 10,
      waitMins: Math.floor(Math.random() * 20) + 5,
      efficiencyScore: Math.floor(Math.random() * 30) + 70 // 70 to 100% staff efficiency
    });
  }
  return data;
};

export default function QueueChart() {
  const [data, setData] = useState<any[]>([]);
  const [isMounted, setIsMounted] = useState(false);

  useEffect(() => {
    setData(generateMockTrafficData());
    setIsMounted(true);
  }, []);

  if (!isMounted) {
    return (
      <div className="w-full h-[400px] bg-slate-50 dark:bg-slate-900/50 p-6 rounded-[2rem] border border-slate-200 dark:border-slate-800 animate-pulse flex flex-col justify-between">
         <div className="space-y-2">
            <div className="h-6 w-48 bg-slate-200 dark:bg-slate-800 rounded-lg"></div>
            <div className="h-4 w-32 bg-slate-200 dark:bg-slate-800 rounded-lg"></div>
         </div>
         <div className="h-[250px] w-full bg-slate-100 dark:bg-slate-800/50 rounded-xl mt-6"></div>
      </div>
    );
  }

  return (
    <div className="w-full h-[400px] bg-white dark:bg-slate-900 p-6 rounded-[2rem] border border-slate-200 dark:border-slate-800 shadow-sm transition-colors">
      <div className="mb-6">
        <h3 className="text-xl font-bold text-slate-800 dark:text-slate-100">Daily Customer Traffic</h3>
        <p className="text-sm text-slate-500 dark:text-slate-400">Total visitors per hour</p>
      </div>

      <div className="w-full h-[300px]">
        <ResponsiveContainer width="100%" height="100%" minWidth={1} minHeight={1}>
          <AreaChart data={data} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
            <defs>
              <linearGradient id="colorCustomers" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.3}/>
                <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
              </linearGradient>
            </defs>
            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#334155" opacity={0.2} />
            <XAxis 
              dataKey="time" 
              axisLine={false} 
              tickLine={false} 
              tick={{ fill: '#64748b', fontSize: 12 }} 
              dy={10} 
            />
            <YAxis 
              axisLine={false} 
              tickLine={false} 
              tick={{ fill: '#64748b', fontSize: 12 }} 
            />
            <Tooltip 
              contentStyle={{ 
                backgroundColor: 'rgba(15, 23, 42, 0.9)', 
                borderRadius: '16px',
                border: 'none',
                color: '#fff',
                fontFamily: 'sans-serif',
                boxShadow: '0 10px 25px -5px rgba(0, 0, 0, 0.2)'
              }} 
            />
            <Legend verticalAlign="top" height={36} iconType="circle" />

            <Area 
              type="monotone" 
              dataKey="customers" 
              name="Flow (Tokens)"
              stroke="#3b82f6" 
              strokeWidth={3}
              fillOpacity={1} 
              fill="url(#colorCustomers)" 
              activeDot={{ r: 6, strokeWidth: 0 }}
            />

            <Line 
              type="monotone" 
              dataKey="efficiencyScore"
              name="Staff Efficiency (%)" 
              stroke="#10b981" 
              strokeWidth={2}
              strokeDasharray="5 5"
              dot={false}
            />

            <Line 
              type="monotone" 
              dataKey="waitMins"
              name="Avg Wait (Mins)" 
              stroke="#f59e0b" 
              strokeWidth={2}
              dot={{ r: 4 }}
            />
          </AreaChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import dynamic from 'next/dynamic';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Star, MapPin, Clock, Share2, ShieldCheck, 
  ChevronDown, MessageCircle, Copy, QrCode, ArrowRight, Zap, Globe 
} from 'lucide-react';
import { createClient } from "@/lib/supabase/client";

const supabase = createClient();
import Link from 'next/link';
const QRCodeSVG = dynamic(() => import('qrcode.react').then(m => ({ default: m.QRCodeSVG })), { ssr: false });
import { toast } from 'sonner';
import { useAuth } from '@/context/AuthContext';
import { useLanguage } from '@/context/LanguageContext';
import { useRouter } from 'next/navigation';
import { useGuestSession } from '@/hooks/useGuestSession';
import { haversineDistance as getDistance } from '@/lib/geolocation';
import { EmailOTPModal } from '@/components/auth/EmailOTPModal';
import FastPassCheckout from '@/components/FastPassCheckout';
import CustomerOnboarding from '@/components/Onboarding/CustomerOnboarding';
import { AlertCircle, LogIn, User as UserIcon, Activity as ActivityIcon } from 'lucide-react';
import { track } from '@/lib/analytics';

interface PublicBusinessClientProps {
  business: any;
  initialWaitingCount: number;
  initialReviews: any[];
}

export default function PublicBusinessClient({ business, initialWaitingCount, initialReviews }: PublicBusinessClientProps) {
  const router = useRouter();
  const { user, isAuthenticated, userRole } = useAuth();
  const { t } = useLanguage();
  const { guestVisit, isLoaded, isReturningGuest, guestName, guestPhone, saveGuestSession } = useGuestSession(business.id);

  const [waitingCount, setWaitingCount] = useState(initialWaitingCount);
  const [showHours, setShowHours] = useState(false);
  const [showQR, setShowQR] = useState(false);
  
  // Join Flow States
  const [isJoining, setIsJoining] = useState(false);
  const [joinMode, setJoinMode] = useState<'info' | 'choose' | 'guest' | 'account'>('info');
  const [name, setName] = useState("");
  const [phone, setPhone] = useState("");
  const [phoneError, setPhoneError] = useState("");
  const [notifyWhatsApp, setNotifyWhatsApp] = useState(true);
  const [joinedToken, setJoinedToken] = useState<any>(null);
  const [isAuthOpen, setIsAuthOpen] = useState(false);
  const [distance, setDistance] = useState<number | null>(null);
  const [liveServingToken, setLiveServingToken] = useState<string | null>(null);

  // Prefill from auth or guest session
  useEffect(() => {
    if (!isLoaded) return;
    if (user) {
      setName(user.user_metadata?.full_name || "");
      const rawPhone = user.phone?.replace("+91", "") || "";
      if (rawPhone.length === 10) setPhone(rawPhone);
    } else if (isReturningGuest) {
      setName(guestName);
      setPhone(guestPhone);
    }
  }, [user, isLoaded, isReturningGuest, guestName, guestPhone]);

  // Fetch Live Serving Token
  useEffect(() => {
    const fetchServing = async () => {
      const { data } = await supabase.from("tokens")
        .select("tokenNumber")
        .eq("orgId", business.id)
        .eq("status", "SERVING")
        .order("updatedAt", { ascending: false })
        .limit(1)
        .maybeSingle();
      if (data) setLiveServingToken(data.tokenNumber);
    };
    fetchServing();
    
    // Track page view
    track('page_view', { business_id: business.id });
  }, [business.id]);

  // --- REAL-TIME UPDATES ---
  useEffect(() => {
    if (!business?.id) return;

    const channel = supabase
      .channel(`public:tokens:${business.id}`)
      .on('postgres_changes', {
        event: '*',
        schema: 'public',
        table: 'tokens',
        filter: `orgId=eq.${business.id}`
      }, async () => {
        // Refetch total waiting on any change
        const { count } = await supabase
          .from('tokens')
          .select('*', { count: 'exact', head: true })
          .eq('orgId', business.id)
          .eq('status', 'WAITING')
          .gte('createdAt', new Date().toISOString().split('T')[0]);
        
        setWaitingCount(count || 0);
      })
      .subscribe();

    return () => {
      channel.unsubscribe();
    };
  }, [business.id]);

  // Handle Geolocation for Fast Pass
  useEffect(() => {
    if (business?.latitude && business?.longitude) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          const dist = getDistance(
            pos.coords.latitude, pos.coords.longitude,
            business.latitude, business.longitude
          );
          setDistance(dist);
        },
        (err) => console.warn("Location access denied", err)
      );
    }
  }, [business]);

  // Check for active token in localStorage on mount
  useEffect(() => {
    if (!isLoaded) return;
    const savedOrg = localStorage.getItem("active_org");
    const savedToken = localStorage.getItem("active_token");
    const savedTokenNumber = localStorage.getItem("active_token_number");
    
    if (savedOrg === business.id && savedToken) {
      setJoinedToken({
        tokenId: savedToken,
        tokenNumber: savedTokenNumber || "Refetching...",
        position: "?",
        estimatedWaitMins: "?",
        isGuest: !isAuthenticated
      });
    }
  }, [business.id, isLoaded, isAuthenticated]);

  const handleJoinQueue = async (asGuest: boolean) => {
    if (!name.trim()) { setPhoneError("Name is required"); return; }
    
    const normalizePhone = (p: string) => {
      let cleaned = p.replace(/\D/g, "");
      if (cleaned.startsWith("91") && cleaned.length === 12) {
        cleaned = cleaned.substring(2);
      } else if (cleaned.startsWith("0") && cleaned.length === 11) {
        cleaned = cleaned.substring(1);
      }
      return cleaned;
    };

    const digits = normalizePhone(phone);

    if (asGuest) {
      if (!/^[6-9]\d{9}$/.test(digits)) { 
        setPhoneError("Please enter a valid 10-digit Indian mobile number"); 
        return; 
      }
    }

    setIsJoining(true);
    try {
      const counterPrefix = business?.services?.[0]?.prefix || "Q";
      const userId = asGuest ? null : user?.id;
      const customerPhone = asGuest ? "+91" + digits : user?.phone || "+91" + digits;

      const response = await fetch("/api/queue/join", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ 
          orgId: business.id, 
          counterPrefix, 
          userId, 
          customerName: name.trim(), 
          customerPhone 
        })
      });

      const data = await response.json();
      if (!response.ok) throw new Error(data.error || "Failed to join queue");
      
      // Persist guest session
      if (asGuest) {
        saveGuestSession({ 
          name: name.trim(), 
          phone: phone.replace(/\D/g, ""), 
          activeTokenId: data.id, 
          activeTokenNumber: data.tokenNumber 
        });

        // UX-1: WhatsApp-First flow trigger
        if (notifyWhatsApp && business?.phone) {
          const message = `Hi, my token number is ${data.tokenNumber}. Please let me know when it's my turn.`;
          window.open(`https://wa.me/${business.phone.replace(/\D/g, '')}?text=${encodeURIComponent(message)}`, '_blank');
        }
      }

      setJoinedToken({ 
        tokenNumber: data.tokenNumber, 
        estimatedWaitMins: data.estimatedWaitMins, 
        position: waitingCount + 1, 
        isGuest: asGuest, 
        tokenId: data.id,
        orgId: business.id
      });

      // Growth Logic: Set flag for PWA banner
      localStorage.setItem('has_joined_queue', 'true');

      // Tactile Feedback (Haptics)
      if (navigator.vibrate) {
        navigator.vibrate([100, 50, 100, 50, 200]);
      }

      // Audio Feedback
      try {
        const chime = new Audio('/chime.mp3');
        chime.volume = 0.5;
        chime.play().catch(() => {});
      } catch (e) {
        console.warn("Audio feedback failed");
      }

      // Redirect to the live tracking page after a short delay for confetti
      setTimeout(() => {
        router.push(`/customer/queue/${business.id}/${data.id}`);
      }, 3000);

      // Confetti logic
      const end = Date.now() + 3000;
      const confetti = (await import('canvas-confetti')).default;
      const frame = () => {
        confetti({ particleCount: 5, angle: 60, spread: 55, origin: { x: 0 }, colors: ["#00F5A0", "#00D4FF", "#7000FF"] });
        confetti({ particleCount: 5, angle: 120, spread: 55, origin: { x: 1 }, colors: ["#00F5A0", "#00D4FF", "#7000FF"] });
        if (Date.now() < end) requestAnimationFrame(frame);
      };
      frame();
      track('queue_joined', { 
        business_id: business.id, 
        category: business.category || 'General',
        mode: asGuest ? 'guest' : 'account'
      });
      toast.success("Joined successfully!");
    } catch (e: any) {
      console.error("Join Error:", e);
      toast.error("Failed to join queue. Our servers are busy.");
    } finally {
      setIsJoining(false);
    }
  };

  const handleCopyLink = () => {
    navigator.clipboard.writeText(window.location.href);
    toast.success("Link copied to clipboard!");
  };

  const handleShareWhatsApp = () => {
    const text = `Hey, check out ${business.name} on QueueLess! You can join their queue digitally and save time: ${window.location.href}`;
    window.open(`https://wa.me/?text=${encodeURIComponent(text)}`, '_blank');
  };

  const isBusinessOpen = () => {
    const now = new Date();
    const dayOfWeek = now.getDay();
    const dayNamesShort = ["sun", "mon", "tue", "wed", "thu", "fri", "sat"];
    const dayKey = dayNamesShort[dayOfWeek];

    // Check JSON hours first
    if (business.op_hours_json?.[dayKey]) {
      const shifts = business.op_hours_json[dayKey];
      if (shifts === null) return false;

      const currentTime = now.getHours() * 60 + now.getMinutes();
      return shifts.some((shift: { open: string; close: string }) => {
        const [sH, sM] = shift.open.split(":").map(Number);
        const [eH, eM] = shift.close.split(":").map(Number);
        return currentTime >= sH * 60 + sM && currentTime <= eH * 60 + eM;
      });
    }

    if (!business.settings?.businessHours) return true; // Fallback
    const day = now.toLocaleDateString("en-US", { weekday: "long" });
    const hours =
      business.settings.businessHours[day] ||
      business.settings.businessHours["default"];
    if (!hours || hours.closed) return false;

    const [start, end] = hours.slots?.[0] || ["09:00", "20:00"];
    const currentTime = now.getHours() * 60 + now.getMinutes();
    const [sH, sM] = start.split(":").map(Number);
    const [eH, eM] = end.split(":").map(Number);

    return currentTime >= sH * 60 + sM && currentTime <= eH * 60 + eM;
  };

  const avgWait = waitingCount * (business.avg_service_time || 5);
  const isOpen = isBusinessOpen();

  return (
    <div className="max-w-xl mx-auto pb-32">
       
       {/* HERO SECTION */}
       <div className="relative h-64 overflow-hidden rounded-b-[3rem]">
          {business.cover_image_url ? (
            <img src={business.cover_image_url} alt={business.name} className="w-full h-full object-cover" />
          ) : (
            <div className="w-full h-full bg-gradient-to-br from-background to-surface flex items-center justify-center">
              <Globe size={48} className="text-white/10" />
            </div>
          )}
          <div className="absolute inset-0 bg-gradient-to-t from-background via-transparent to-transparent" />
          
          <Link href="/" className="absolute top-6 left-6 w-10 h-10 rounded-full bg-black/95 flex items-center justify-center text-white/80 hover:text-white transition-colors">
             <ChevronDown className="rotate-90" size={20} />
          </Link>
       </div>

       <div className="px-6 -mt-12 relative z-10">
          <div className="bg-surface/95 border border-border rounded-brand p-8 shadow-2xl">
             <div className="flex items-center gap-2 mb-4">
                <span className="px-3 py-1 rounded-full bg-emerald-500/10 text-emerald-500 text-[10px] font-black uppercase tracking-widest border border-emerald-500/20">
                   {business.category || "Business"}
                </span>
                   <span className="flex items-center gap-1 text-[10px] font-black uppercase tracking-widest text-blue-400">
                      <ShieldCheck size={12} /> Verified
                   </span>
             </div>

             <h1 className="text-3xl font-black text-white tracking-tighter mb-2">{business.name}</h1>
             
             <div className="flex items-center gap-4 mb-6">
                <div className="flex items-center gap-1 text-amber-500">
                   <Star size={18} fill="currentColor" />
                   <span className="font-black">{business.avg_rating || "0.0"}</span>
                </div>
                <span className="text-zinc-500 text-sm">{business.total_reviews || "0"} reviews</span>
                <div className="h-4 w-px bg-white/10" />
                <a 
                   href={`https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(business.address || "")}`}
                   target="_blank"
                   rel="noopener noreferrer"
                   className="flex items-center gap-1 text-zinc-400 text-sm hover:text-white transition-colors"
                >
                   <MapPin size={14} /> Open Maps
                </a>
             </div>

             <p className="text-zinc-400 text-sm leading-relaxed mb-8">
               {business.description || "The future of waiting is here. Join our digital queue and arrive only when you're called."}
             </p>

             {/* LIVE STATUS CARD */}
             <div className="p-6 rounded-3xl bg-white/[0.03] border border-white/5 mb-8">
                <div className="flex items-center justify-between mb-6">
                   <div className="flex items-center gap-2">
                      <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse shadow-[0_0_10px_#10b981]" />
                      <span className="text-[10px] font-black uppercase tracking-widest text-zinc-500">{t('liveStatus')}</span>
                   </div>
                   <span className={`text-[10px] font-black px-2 py-1 rounded-md ${isOpen ? 'bg-emerald-500/10 text-emerald-500' : 'bg-red-500/10 text-red-500'} uppercase tracking-widest`}>
                      {isOpen ? 'Open Now' : 'Closed'}
                   </span>
                </div>

                <div className="grid grid-cols-2 gap-4">
                   <div className="text-center p-4 rounded-2xl bg-black/40">
                      <p className="text-2xl font-black text-white">0</p>
                      <p className="text-[10px] font-bold text-zinc-500 uppercase mt-1">{t('position')}</p>
                   </div>
                   <div className="text-center p-4 rounded-2xl bg-black/40">
                      <p className="text-2xl font-black text-primary">~{avgWait}m</p>
                      <p className="text-[10px] font-bold text-zinc-500 uppercase mt-1">{t('waitTime')}</p>
                   </div>
                </div>
             </div>

             {/* ACTIONS / JOIN FLOW */}
             <div className="mt-8">
                <AnimatePresence mode="wait">
                  {joinedToken ? (
                    <motion.div 
                      key="success" 
                      initial={{ opacity: 0, scale: 0.95 }} 
                      animate={{ opacity: 1, scale: 1 }}
                      className="text-center p-6 rounded-3xl bg-emerald-500/10 border border-emerald-500/20"
                    >
                       <div className="bg-emerald-500 text-black px-4 py-1 rounded-full text-[10px] font-black uppercase tracking-widest inline-block mb-4">
                          Booking Confirmed
                       </div>
                       <h3 className="text-5xl font-black text-white mb-2 tracking-tighter">{joinedToken.tokenNumber}</h3>
                       <div className="flex justify-center gap-6 mb-6">
                          <div>
                             <p className="text-zinc-500 text-[10px] uppercase font-bold tracking-widest">{t('position')}</p>
                             <p className="text-xl font-black">#{joinedToken.position}</p>
                          </div>
                          <div className="w-px bg-white/10" />
                          <div>
                             <p className="text-zinc-500 text-[10px] uppercase font-bold tracking-widest">{t('waitTime')}</p>
                             <p className="text-xl font-black">{joinedToken.estimatedWaitMins}m</p>
                          </div>
                       </div>

                       {/* PWA Install Banner */}
                       <div className="mb-6 p-4 rounded-2xl bg-white/5 border border-white/10 flex items-center justify-between text-left">
                          <div className="flex-1 pr-4">
                             <p className="text-white font-bold text-xs uppercase tracking-tight">≡ƒô▒ Add to Home Screen</p>
                             <p className="text-zinc-400 text-[10px] mt-0.5">Stay updated even when your screen is off</p>
                          </div>
                          <button 
                             onClick={() => window.dispatchEvent(new Event('trigger-pwa-install'))}
                             className="px-4 py-2 bg-emerald-500 text-black font-black text-[10px] uppercase rounded-xl hover:bg-emerald-400 transition-colors"
                          >
                             Add Now
                          </button>
                       </div>

                       <button 
                         onClick={() => router.push(`/track/${joinedToken.tokenId}`)}
                         className="w-full py-4 rounded-2xl bg-white text-black font-black uppercase tracking-widest text-xs hover:brightness-110 active:scale-95 transition-all shadow-xl"
                       >
                          Track Progress <ArrowRight size={16} className="inline ml-1" />
                       </button>
                    </motion.div>
                  ) : joinMode === 'info' ? (
                    <motion.div key="info" initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
                       {userRole === "business_owner" ? (
                         <div className="w-full p-6 py-8 rounded-[2rem] bg-indigo-500/10 border border-indigo-500/20 text-center">
                            <ShieldCheck size={32} className="mx-auto text-indigo-400 mb-3" />
                            <p className="text-white font-bold">Business Owner View</p>
                            <p className="text-zinc-500 text-xs mt-1">You are viewing this as a business owner. Queue joining is disabled for your role.</p>
                            <button 
                              onClick={() => router.push('/dashboard')}
                              className="mt-6 text-indigo-400 font-black uppercase tracking-widest text-[10px] hover:underline"
                            >
                              Go to My Dashboard
                            </button>
                         </div>
                       ) : (
                         <>
                           <button 
                             disabled={!isOpen}
                             onClick={() => setJoinMode(isAuthenticated ? 'account' : 'choose')}
                             className="btn-primary w-full py-5 text-sm"
                           >
                              {isOpen ? <>{t('joinQueue')} <ArrowRight size={18} /></> : "Closed for now"}
                           </button>

                           {business.settings?.fastPassEnabled && isOpen && (
                              <div className="mt-4 flex items-center justify-center gap-2 text-[10px] font-black uppercase tracking-widest text-primary bg-primary/5 py-3 rounded-2xl border border-primary/10">
                                 <Zap size={14} fill="currentColor" /> Skip the line for Γé╣{business.settings?.fastPassPrice || 49}
                              </div>
                           )}
                         </>
                       )}
                    </motion.div>
                  ) : joinMode === 'choose' ? (
                    <motion.div key="choose" initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className="space-y-4">
                        <button 
                          onClick={() => setJoinMode('guest')}
                          className="w-full flex items-start gap-4 p-5 rounded-3xl bg-white/5 border border-white/10 text-left hover:bg-white/10 transition-all group"
                        >
                           <div className="w-12 h-12 rounded-2xl bg-primary/10 flex items-center justify-center text-primary shrink-0">
                              <Zap size={20} />
                           </div>
                           <div>
                              <p className="font-black text-white text-sm">Quick Join (Guest)</p>
                              <p className="text-zinc-500 text-xs mt-1">Join in seconds. No account needed.</p>
                           </div>
                        </button>
                        <button 
                          onClick={() => setIsAuthOpen(true)}
                          className="w-full flex items-start gap-4 p-5 rounded-3xl bg-indigo-500/5 border border-indigo-500/10 text-left hover:bg-indigo-500/10 transition-all"
                        >
                           <div className="w-12 h-12 rounded-2xl bg-indigo-500/10 flex items-center justify-center text-indigo-400 shrink-0">
                              <LogIn size={20} />
                           </div>
                           <div>
                              <p className="font-black text-white text-sm">Join with Account</p>
                              <p className="text-zinc-500 text-xs mt-1">Get SMS alerts and track visits.</p>
                           </div>
                        </button>
                    </motion.div>
                  ) : joinMode === 'guest' ? (
                    <motion.div key="guest" initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} className="space-y-4">
                       <div className="space-y-3">
                          <input 
                            type="text" 
                            placeholder={t('yourName') || "Your Name"} 
                            value={name} 
                            onChange={e => setName(e.target.value)}
                            className="input-dark w-full px-5 py-4"
                          />
                          <div className="flex bg-black/40 border border-border rounded-2xl overflow-hidden focus-within:border-primary transition-colors">
                             <span className="px-4 py-4 text-zinc-500 font-black">+91</span>
                             <input 
                               type="tel" 
                               placeholder={t('mobileNumber') || "Mobile Number"} 
                               value={phone} 
                               onChange={e => setPhone(e.target.value.replace(/\D/g, '').slice(0, 10))}
                               className="bg-transparent flex-1 py-4 pr-5 text-white font-bold outline-none"
                             />
                          </div>
                          {phoneError && <p className="text-red-500 text-[10px] font-black uppercase px-2">{phoneError}</p>}
                       </div>
                       
                       <div className="flex gap-2">
                          <button 
                            disabled={isJoining}
                            onClick={() => handleJoinQueue(true)}
                            className="btn-primary flex-1 py-4 text-xs"
                          >
                             {isJoining ? <ActivityIcon className="animate-spin mx-auto" /> : (t('join') || "Join Now")}
                          </button>
                          
                          {business.settings?.fastPassEnabled && (
                             <FastPassCheckout 
                                businessId={business.id}
                                businessName={business.name}
                                amount={business.settings?.fastPassPrice || 49}
                                tokenData={{
                                   orgId: business.id,
                                   counterPrefix: business.services?.[0]?.prefix || "Q",
                                   customerName: name,
                                   customerPhone: "+91" + phone
                                }}
                                onSuccess={(data) => {
                                   saveGuestSession({ 
                                      name, phone, 
                                      activeTokenId: data.tokenId, 
                                      activeTokenNumber: data.tokenNumber 
                                   });
                                   setJoinedToken({ 
                                      tokenNumber: data.tokenNumber, 
                                      position: 1, 
                                      estimatedWaitMins: 5, 
                                      isGuest: true, 
                                      tokenId: data.tokenId 
                                   });
                                }}
                                onError={(err) => toast.error(err)}
                                isLoading={isJoining}
                             />
                          )}
                       </div>
                    </motion.div>
                  ) : (
                    <motion.div key="account" initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }}>
                       <div className="flex items-center gap-3 p-4 bg-indigo-500/10 rounded-2xl border border-indigo-500/20 mb-6">
                          <div className="w-10 h-10 rounded-full bg-indigo-500 flex items-center justify-center text-white font-black">
                             {(user?.user_metadata?.full_name || "U")[0].toUpperCase()}
                          </div>
                          <div>
                             <p className="font-bold text-white text-sm">{user?.user_metadata?.full_name || "User"}</p>
                             <p className="text-indigo-400 text-[10px] font-black uppercase">Verified Account</p>
                          </div>
                       </div>
                       <button 
                         disabled={isJoining}
                         onClick={() => handleJoinQueue(false)}
                         className="btn-primary w-full py-5 text-sm"
                       >
                          {isJoining ? <ActivityIcon className="animate-spin mx-auto" /> : "Confirm & Join"}
                       </button>
                    </motion.div>
                  )}
                </AnimatePresence>
             </div>
          </div>

          {/* HOURS SECTION */}
          <div className="mt-6">
             <button 
                onClick={() => setShowHours(!showHours)}
                className="w-full flex items-center justify-between p-6 bg-surface border border-border rounded-brand text-sm text-zinc-300 font-bold"
             >
                <div className="flex items-center gap-3">
                   <Clock size={16} className="text-emerald-500" />
                   Operating Hours
                </div>
                <ChevronDown className={`transition-transform duration-300 ${showHours ? 'rotate-180' : ''}`} size={16} />
             </button>
             
             <AnimatePresence>
                {showHours && (
                  <motion.div
                    initial={{ height: 0, opacity: 0 }}
                    animate={{ height: "auto", opacity: 1 }}
                    exit={{ height: 0, opacity: 0 }}
                    className="overflow-hidden"
                  >
                     <div className="p-6 pt-2 space-y-3 bg-surface/50 rounded-b-brand border-x border-b border-border">
                        {[
                          "Monday",
                          "Tuesday",
                          "Wednesday",
                          "Thursday",
                          "Friday",
                          "Saturday",
                          "Sunday",
                        ].map((day) => {
                          const dayKey = day.toLowerCase().slice(0, 3);
                          const jsonHours = business.op_hours_json?.[dayKey];

                          if (jsonHours !== undefined) {
                            return (
                              <div
                                key={day}
                                className="flex justify-between items-center text-xs font-medium"
                              >
                                <span className="text-zinc-500">{day}</span>
                                <span className="text-white">
                                  {jsonHours === null
                                    ? "Closed"
                                    : jsonHours
                                        .map((s: { open: string; close: string }) => `${s.open} - ${s.close}`)
                                        .join(", ")}
                                </span>
                              </div>
                            );
                          }

                          const hours = business.settings?.businessHours?.[day] || {
                            slots: [["09:00", "20:00"]],
                          };
                          return (
                            <div
                              key={day}
                              className="flex justify-between items-center text-xs font-medium"
                            >
                              <span className="text-zinc-500">{day}</span>
                              <span className="text-white">
                                {hours.closed
                                  ? "Closed"
                                  : `${hours.slots?.[0]?.[0]} - ${hours.slots?.[0]?.[1]}`}
                              </span>
                            </div>
                          );
                        })}
                     </div>
                  </motion.div>
                )}
             </AnimatePresence>
          </div>

          {/* REVIEWS SECTION */}
          <div className="mt-8">
             <h3 className="text-sm font-black uppercase tracking-[0.3em] text-zinc-600 mb-6 pl-2">Customer Feedback</h3>
             {initialReviews.length > 0 ? (
               <div className="space-y-4">
                  {initialReviews.map((review) => (
                    <motion.div 
                      key={review.id}
                      initial={{ opacity: 0, y: 10 }}
                      animate={{ opacity: 1, y: 0 }}
                      className="p-6 rounded-brand bg-surface border border-border"
                    >
                       <div className="flex items-center gap-1 mb-2">
                          {[...Array(5)].map((_, i) => (
                             <Star key={i} size={12} fill={i < review.rating ? "var(--brand-primary)" : "transparent"} stroke={i < review.rating ? "var(--brand-primary)" : "#4b5563"} />
                          ))}
                       </div>
                       <p className="text-sm text-zinc-300 leading-relaxed italic mb-3">"{review.comment}"</p>
                       <p className="text-[10px] font-black uppercase tracking-widest text-zinc-600">Verified Visit ΓÇó 2 hours ago</p>
                    </motion.div>
                  ))}
               </div>
             ) : (
                <div className="p-8 text-center bg-surface border border-border rounded-brand">
                   <p className="text-xs font-bold text-zinc-600 uppercase tracking-widest">No reviews yet. Be the first!</p>
                </div>
             )}
          </div>

          {/* SHARE ROW */}
          <div className="mt-8 grid grid-cols-3 gap-4">
             <button 
                onClick={handleShareWhatsApp}
                className="flex flex-col items-center justify-center p-6 rounded-brand bg-surface border border-border text-emerald-500 hover:opacity-80 transition-all"
             >
                <MessageCircle size={24} />
                <span className="text-[10px] font-black uppercase tracking-widest mt-2">WhatsApp</span>
             </button>
             <button 
                onClick={handleCopyLink}
                className="flex flex-col items-center justify-center p-6 rounded-brand bg-surface border border-border text-blue-400 hover:opacity-80 transition-all"
             >
                <Copy size={24} />
                <span className="text-[10px] font-black uppercase tracking-widest mt-2">Copy Link</span>
             </button>
             <button 
                onClick={() => setShowQR(true)}
                className="flex flex-col items-center justify-center p-6 rounded-brand bg-surface border border-border text-white hover:opacity-80 transition-all"
             >
                <QrCode size={24} />
                <span className="text-[10px] font-black uppercase tracking-widest mt-2">QR Code</span>
             </button>
          </div>
       </div>

       {/* DISTANCE WARNING MODAL */}
       <AnimatePresence>
          {distance !== null && distance > 5 && joinMode === 'guest' && !joinedToken && (
            <motion.div 
              initial={{ opacity: 0 }} 
              animate={{ opacity: 1 }} 
              exit={{ opacity: 0 }} 
              className="fixed inset-0 z-[110] bg-black/95 flex items-end p-6"
            >
               <motion.div initial={{ y: 20 }} animate={{ y: 0 }} className="w-full max-w-lg mx-auto bg-surface border border-border rounded-brand p-8">
                  <div className="w-16 h-16 rounded-full bg-amber-500/10 flex items-center justify-center text-amber-500 mb-6 mx-auto">
                     <AlertCircle size={32} />
                  </div>
                  <h3 className="text-2xl font-black text-white text-center mb-2">You're bit far!</h3>
                  <p className="text-zinc-500 text-center text-sm mb-8">
                     You are <span className="text-white font-bold">{distance.toFixed(1)}km</span> away. We recommend joining only if you can reach within the wait time.
                  </p>
                  <div className="flex gap-4">
                     <button onClick={() => setDistance(null)} className="flex-1 py-4 rounded-2xl bg-white/5 border border-white/10 text-white font-bold">Cancel</button>
                     <button onClick={() => setDistance(null)} className="flex-1 py-4 rounded-2xl bg-amber-500 text-black font-black">Continue</button>
                  </div>
               </motion.div>
            </motion.div>
          )}
       </AnimatePresence>

       {/* QR MODAL */}
       <AnimatePresence>
          {showQR && (
            <motion.div 
               initial={{ opacity: 0 }}
               animate={{ opacity: 1 }}
               exit={{ opacity: 0 }}
               className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/95"
               onClick={() => setShowQR(false)}
            >
               <motion.div 
                  initial={{ scale: 0.9, opacity: 0 }}
                  animate={{ scale: 1, opacity: 1 }}
                  exit={{ scale: 0.9, opacity: 0 }}
                  className="bg-surface border border-border rounded-brand p-12 flex flex-col items-center text-center"
                  onClick={e => e.stopPropagation()}
               >
                  <div className="p-4 bg-white rounded-3xl mb-8">
                     <QRCodeSVG value={typeof window !== 'undefined' ? window.location.href : business.id} size={200} />
                  </div>
                  <h3 className="text-xl font-black text-white mb-2 tracking-tight">Scan to Share</h3>
                  <p className="text-xs text-zinc-500 font-bold uppercase tracking-widest">Share ${business.name} with friends</p>
               </motion.div>
            </motion.div>
          )}
       </AnimatePresence>

       {/* Email Auth Modal */}
       {isAuthOpen && (
         <EmailOTPModal 
           onClose={() => setIsAuthOpen(false)}
           onSuccess={() => {
             setIsAuthOpen(false);
             setJoinMode('account');
           }}
         />
       )}
       
       <CustomerOnboarding />
    </div>
  );
}

'use client';

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Building2, MapPin, Phone, FileText, Clock, ChevronRight, Loader2 } from 'lucide-react';
import { toast } from 'sonner';

interface BusinessCreationModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSuccess: (business: any) => void;
}

const CATEGORIES = [
  "Hospital", "Bank", "Temple", "Government", 
  "Railway Station", "Court", "Post Office"
];

export default function BusinessCreationModal({ isOpen, onClose, onSuccess }: BusinessCreationModalProps) {
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    category: 'Hospital',
    location: '',
    phone: '',
    description: '',
    serviceMins: '15'
  });

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    try {
      const res = await fetch('/api/business/create', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData)
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data.error || 'Failed to create business');

      toast.success('Business created successfully!');
      onSuccess(data);
      onClose();
    } catch (err: any) {
      toast.error(err.message);
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className="absolute inset-0 bg-black/60 bg-opacity-95"
      />
      
      <motion.div 
        initial={{ opacity: 0, scale: 0.9, y: 20 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.9, y: 20 }}
        className="relative w-full max-w-lg bg-surface border border-border rounded-[2.5rem] p-8 shadow-2xl overflow-hidden"
      >
        {/* Background Accent */}
        <div className="absolute top-0 right-0 w-32 h-32 bg-primary/10 rounded-full blur-[60px] -mr-16 -mt-16" />
        
        <div className="flex justify-between items-center mb-8 relative z-10">
          <div>
            <h2 className="text-2xl font-black text-white tracking-tight">Create Listing</h2>
            <p className="text-zinc-500 text-xs font-bold uppercase tracking-widest mt-1">Step 1 of 3</p>
          </div>
          <button onClick={onClose} className="w-10 h-10 rounded-full bg-white/5 flex items-center justify-center text-zinc-400 hover:text-white transition-colors">
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5 relative z-10">
          <div className="grid grid-cols-1 gap-5">
            <div>
              <label className="block text-[10px] font-black uppercase tracking-widest text-zinc-500 mb-2 ml-1">Business Name</label>
              <div className="relative">
                <Building2 size={16} className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-500" />
                <input 
                  type="text"
                  required
                  placeholder="e.g. City General Hospital"
                  className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-4 text-white placeholder:text-zinc-600 focus:outline-none focus:border-primary transition-all text-sm font-medium"
                  value={formData.name}
                  onChange={e => setFormData({...formData, name: e.target.value})}
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] font-black uppercase tracking-widest text-zinc-500 mb-2 ml-1">Category</label>
                <select 
                  className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 px-4 text-white focus:outline-none focus:border-primary transition-all text-sm font-medium appearance-none"
                  value={formData.category}
                  onChange={e => setFormData({...formData, category: e.target.value})}
                >
                  {CATEGORIES.map(cat => (
                    <option key={cat} value={cat} className="bg-zinc-900">{cat}</option>
                  ))}
                </select>
              </div>
              <div>
                <label className="block text-[10px] font-black uppercase tracking-widest text-zinc-500 mb-2 ml-1">Location (City)</label>
                <div className="relative">
                  <MapPin size={16} className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-500" />
                  <input 
                    type="text"
                    required
                    placeholder="e.g. Delhi"
                    className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-4 text-white placeholder:text-zinc-600 focus:outline-none focus:border-primary transition-all text-sm font-medium"
                    value={formData.location}
                    onChange={e => setFormData({...formData, location: e.target.value})}
                  />
                </div>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] font-black uppercase tracking-widest text-zinc-500 mb-2 ml-1">Phone</label>
                <div className="relative">
                  <Phone size={16} className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-500" />
                  <input 
                    type="tel"
                    required
                    placeholder="+91 98765..."
                    className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-4 text-white placeholder:text-zinc-600 focus:outline-none focus:border-primary transition-all text-sm font-medium"
                    value={formData.phone}
                    onChange={e => setFormData({...formData, phone: e.target.value})}
                  />
                </div>
              </div>
              <div>
                <label className="block text-[10px] font-black uppercase tracking-widest text-zinc-500 mb-2 ml-1">Service Mins/Person</label>
                <div className="relative">
                  <Clock size={16} className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-500" />
                  <input 
                    type="number"
                    required
                    min="1"
                    className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-4 text-white placeholder:text-zinc-600 focus:outline-none focus:border-primary transition-all text-sm font-medium"
                    value={formData.serviceMins}
                    onChange={e => setFormData({...formData, serviceMins: e.target.value})}
                  />
                </div>
              </div>
            </div>

            <div>
              <label className="block text-[10px] font-black uppercase tracking-widest text-zinc-500 mb-2 ml-1">Description</label>
              <div className="relative">
                <FileText size={16} className="absolute left-4 top-4 text-zinc-500" />
                <textarea 
                  placeholder="Tell customers about your services..."
                  className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-4 text-white placeholder:text-zinc-600 focus:outline-none focus:border-primary transition-all text-sm font-medium min-h-[100px] resize-none"
                  value={formData.description}
                  onChange={e => setFormData({...formData, description: e.target.value})}
                />
              </div>
            </div>
          </div>

          <button 
            type="submit"
            disabled={loading}
            className="w-full btn-primary py-5 rounded-[1.2rem] mt-4 flex items-center justify-center gap-2 group shadow-xl shadow-primary/20"
          >
            {loading ? (
              <Loader2 className="animate-spin" size={20} />
            ) : (
              <>
                Create Business <ChevronRight size={20} className="group-hover:translate-x-1 transition-transform" />
              </>
            )}
          </button>
        </form>
      </motion.div>
    </div>
  );
}

'use client';

import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { CheckCircle2, Circle, Clock, Zap, ArrowRight, Loader2, Play } from 'lucide-react';
import { createClient } from '@/lib/supabase/client';
import { toast } from 'sonner';

const supabase = createClient();
import BusinessCreationModal from './BusinessCreationModal';

interface OnboardingChecklistProps {
  business: any;
  onUpdate: () => void;
}

export default function OnboardingChecklist({ business, onUpdate }: OnboardingChecklistProps) {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [step2Data, setStep2Data] = useState({
    serviceMins: business?.serviceMins || 15,
    open: '09:00',
    close: '18:00'
  });

  const step1Complete = !!business;
  const step2Complete = step1Complete && (business.onboarding_step >= 3 || business.claim_status === 'active');
  const currentStep = !step1Complete ? 1 : (business.claim_status === 'claimed' ? 2 : 3);

  const handleStep2Submit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      const { error } = await supabase
        .from('businesses')
        .update({
          serviceMins: step2Data.serviceMins,
          opHours: { open: step2Data.open, close: step2Data.close },
          onboarding_step: 3
        })
        .eq('id', business.id);

      if (error) throw error;
      toast.success('Queue settings saved!');
      onUpdate();
    } catch (err: any) {
      toast.error(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleActivateQueue = async () => {
    setLoading(true);
    try {
      const { error } = await supabase.rpc('activate_queue_for_today', {
        p_org_id: business.id
      });

      if (error) throw error;

      // Also mark business as active
      await supabase.from('businesses').update({ claim_status: 'active' }).eq('id', business.id);

      toast.success('Queue is now LIVE! ≡ƒÜÇ');
      onUpdate();
    } catch (err: any) {
      toast.error(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-xl mx-auto py-12 px-6">
      <div className="text-center mb-12">
        <h1 className="text-4xl font-black text-white tracking-tighter mb-4">≡ƒÅó Welcome to QueueLess Business</h1>
        <p className="text-zinc-500 font-medium">Let's get your queue live in 3 simple steps</p>
      </div>

      <div className="space-y-6">
        {/* STEP 1 */}
        <div className={`p-6 rounded-[2rem] border transition-all ${step1Complete ? 'bg-primary/5 border-primary/20' : 'bg-white/5 border-white/10'}`}>
          <div className="flex items-center gap-4">
            <div className={`w-8 h-8 rounded-full flex items-center justify-center ${step1Complete ? 'bg-primary text-black' : 'bg-zinc-800 text-zinc-500'}`}>
              {step1Complete ? <CheckCircle2 size={18} /> : 1}
            </div>
            <div className="flex-1">
              <h3 className={`font-bold ${step1Complete ? 'text-white' : 'text-zinc-400'}`}>Step 1: Create or claim your business listing</h3>
              {currentStep === 1 && (
                <button 
                  onClick={() => setIsModalOpen(true)}
                  className="mt-4 btn-primary py-3 px-6 text-xs flex items-center gap-2"
                >
                  Get Started <ArrowRight size={14} />
                </button>
              )}
            </div>
          </div>
        </div>

        {/* STEP 2 */}
        <div className={`p-6 rounded-[2rem] border transition-all ${step2Complete ? 'bg-primary/5 border-primary/20' : currentStep === 2 ? 'bg-white/5 border-primary/30' : 'bg-white/5 border-white/10 opacity-50'}`}>
          <div className="flex items-center gap-4">
            <div className={`w-8 h-8 rounded-full flex items-center justify-center ${step2Complete ? 'bg-primary text-black' : currentStep === 2 ? 'bg-primary/10 text-primary' : 'bg-zinc-800 text-zinc-500'}`}>
              {step2Complete ? <CheckCircle2 size={18} /> : 2}
            </div>
            <div className="flex-1">
              <h3 className={`font-bold ${currentStep >= 2 ? 'text-white' : 'text-zinc-400'}`}>Step 2: Set your queue hours and service time</h3>
              {currentStep === 2 && (
                <form onSubmit={handleStep2Submit} className="mt-6 space-y-4">
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-[8px] font-black uppercase text-zinc-500 mb-1">Service Mins</label>
                      <input 
                        type="number"
                        className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2 text-sm text-white"
                        value={step2Data.serviceMins}
                        onChange={e => setStep2Data({...step2Data, serviceMins: parseInt(e.target.value)})}
                      />
                    </div>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-[8px] font-black uppercase text-zinc-500 mb-1">Opens at</label>
                      <input 
                        type="time"
                        className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2 text-sm text-white"
                        value={step2Data.open}
                        onChange={e => setStep2Data({...step2Data, open: e.target.value})}
                      />
                    </div>
                    <div>
                      <label className="block text-[8px] font-black uppercase text-zinc-500 mb-1">Closes at</label>
                      <input 
                        type="time"
                        className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2 text-sm text-white"
                        value={step2Data.close}
                        onChange={e => setStep2Data({...step2Data, close: e.target.value})}
                      />
                    </div>
                  </div>
                  <button 
                    type="submit"
                    disabled={loading}
                    className="btn-primary py-3 px-6 text-xs flex items-center gap-2"
                  >
                    {loading ? <Loader2 className="animate-spin" size={14} /> : <>Save Settings <ArrowRight size={14} /></>}
                  </button>
                </form>
              )}
            </div>
          </div>
        </div>

        {/* STEP 3 */}
        <div className={`p-6 rounded-[2rem] border transition-all ${currentStep === 3 ? 'bg-primary/10 border-primary shadow-xl shadow-primary/10' : 'bg-white/5 border-white/10 opacity-50'}`}>
          <div className="flex items-center gap-4">
            <div className={`w-8 h-8 rounded-full flex items-center justify-center ${currentStep === 3 ? 'bg-primary text-black animate-pulse' : 'bg-zinc-800 text-zinc-500'}`}>
              3
            </div>
            <div className="flex-1">
              <h3 className={`font-bold ${currentStep === 3 ? 'text-white' : 'text-zinc-400'}`}>Step 3: Activate today's queue and get your QR code</h3>
              {currentStep === 3 && (
                <div className="mt-6">
                  <p className="text-zinc-400 text-sm mb-6">Everything looks good! Ready to welcome your first digital customer?</p>
                  <button 
                    onClick={handleActivateQueue}
                    disabled={loading}
                    className="w-full py-5 bg-emerald-500 text-black font-black uppercase tracking-widest text-sm rounded-2xl flex items-center justify-center gap-3 hover:bg-emerald-400 transition-all shadow-xl shadow-emerald-500/20 active:scale-95"
                  >
                    {loading ? <Loader2 className="animate-spin" size={20} /> : <><Play size={20} fill="currentColor" /> Activate Queue for Today</>}
                  </button>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      <BusinessCreationModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onSuccess={onUpdate}
      />
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Crown, AlertCircle, ArrowUpCircle } from 'lucide-react';
import UpgradeModal from '../pricing/UpgradeModal';

