'use client';

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Users, UserPlus, X, Shield, ToggleRight, ToggleLeft, Trash2, CheckCircle2, UserCheck } from 'lucide-react';
import { createClient } from '@/lib/supabase/client';
import GlassCard from '@/components/ui/GlassCard';

const supabase = createClient();
import { toast } from 'sonner';

interface StaffMember {
  id: string;
  name: string;
  role: string;
  counter_id: string;
  is_active: boolean;
}

export default function StaffManagement({ businessId }: { businessId: string }) {
  const [staff, setStaff] = useState<StaffMember[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [showAddForm, setShowAddForm] = useState(false);
  const [newStaff, setNewStaff] = useState({ name: '', role: 'Operator', counter_id: 'default' });

  const fetchStaff = async () => {
    if (!businessId) return;
    setIsLoading(true);
    const { data, error } = await (supabase.from('staff_members') as any)
      .select('*')
      .eq('business_id', businessId)
      .order('created_at', { ascending: true });

    if (error) {
      toast.error('Failed to fetch staff');
    } else {
      setStaff(data || []);
    }
    setIsLoading(false);
  };

  useEffect(() => {
    fetchStaff();
  }, [businessId]);

  const handleAddStaff = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!businessId) return;
    const { data, error } = await (supabase.from('staff_members') as any)
      .insert([{ ...newStaff, business_id: businessId, is_active: true }])
      .select()
      .single();

    if (error) {
      toast.error('Error adding staff');
    } else {
      setStaff([...staff, data]);
      setShowAddForm(false);
      setNewStaff({ name: '', role: 'Operator', counter_id: 'default' });
      toast.success('Staff member added');
    }
  };

  const toggleStatus = async (id: string, currentStatus: boolean) => {
    const { error } = await (supabase.from('staff_members') as any)
      .update({ is_active: !currentStatus })
      .eq('id', id);

    if (error) {
      toast.error('Failed to update status');
    } else {
      setStaff(staff.map(s => s.id === id ? { ...s, is_active: !currentStatus } : s));
      toast.success('Status updated');
    }
  };

  const deleteStaff = async (id: string) => {
    if (!confirm('Are you sure you want to remove this staff member?')) return;

    const { error } = await (supabase.from('staff_members') as any)
      .delete()
      .eq('id', id);

    if (error) {
      toast.error('Error removing staff');
    } else {
      setStaff(staff.filter(s => s.id !== id));
      toast.success('Staff removed');
    }
  };

  if (isLoading) {
    return (
      <div className="flex flex-col items-center justify-center py-20 gap-4">
        <div className="w-10 h-10 border-4 border-[#00F5A0]/20 border-t-[#00F5A0] rounded-full animate-spin" />
        <p className="text-[#00F5A0] font-black uppercase tracking-widest text-[10px]">Loading Team...</p>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-xl font-black text-white tracking-tight">Team Management</h2>
          <p className="text-xs text-zinc-500 font-medium">Manage operators and their assigned counters.</p>
        </div>
        <button 
          onClick={() => setShowAddForm(true)}
          className="flex items-center gap-2 px-4 py-2 rounded-xl bg-[#00F5A0] text-[#0A0A0F] font-bold text-xs hover:brightness-110 transition-all shadow-lg shadow-[#00F5A0]/20"
        >
          <UserPlus size={16} /> Add Member
        </button>
      </div>

      <AnimatePresence>
        {showAddForm && (
          <motion.div 
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0, scale: 0.95 }}
            className="p-6 rounded-3xl bg-[#111118] border border-white/10"
          >
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-sm font-black text-white uppercase tracking-widest">New Staff Member</h3>
              <button onClick={() => setShowAddForm(false)} className="text-zinc-500 hover:text-white">
                <X size={20} />
              </button>
            </div>
            <form onSubmit={handleAddStaff} className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <input 
                type="text" 
                placeholder="Full Name"
                required
                value={newStaff.name}
                onChange={e => setNewStaff({...newStaff, name: e.target.value})}
                className="bg-[#0A0A0F] border border-white/10 rounded-xl px-4 py-3 text-white text-sm outline-none focus:border-[#00F5A0]"
              />
              <select 
                value={newStaff.role}
                onChange={e => setNewStaff({...newStaff, role: e.target.value})}
                className="bg-[#0A0A0F] border border-white/10 rounded-xl px-4 py-3 text-white text-sm outline-none focus:border-[#00F5A0]"
              >
                <option value="Operator" className="text-black">Operator</option>
                <option value="Manager" className="text-black">Manager</option>
                <option value="Admin" className="text-black">Admin</option>
              </select>
              <button 
                type="submit"
                className="bg-[#00F5A0] text-[#0A0A0F] font-black uppercase text-[10px] rounded-xl hover:brightness-110"
              >
                Save Member
              </button>
            </form>
          </motion.div>
        )}
      </AnimatePresence>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {staff.map((member) => (
          <GlassCard key={member.id} className="relative overflow-hidden group">
            <div className="flex items-center gap-4">
              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${member.is_active ? 'bg-[#00F5A0]/10 text-[#00F5A0]' : 'bg-zinc-500/10 text-zinc-500'}`}>
                {member.is_active ? <UserCheck size={24} /> : <Users size={24} />}
              </div>
              <div className="flex-1">
                <h4 className="font-black text-white tracking-tight">{member.name}</h4>
                <div className="flex items-center gap-2 mt-1">
                  <span className="text-[10px] font-black uppercase tracking-widest text-zinc-500">{member.role}</span>
                  <span className="w-1 h-1 rounded-full bg-zinc-700" />
                  <span className="text-[10px] font-black uppercase tracking-widest text-zinc-500">Counter: {member.counter_id}</span>
                </div>
              </div>
              <div className="flex items-center gap-2">
                <button 
                  onClick={() => toggleStatus(member.id, member.is_active)}
                  className={`p-2 rounded-lg transition-colors ${member.is_active ? 'text-[#00F5A0] hover:bg-[#00F5A0]/10' : 'text-zinc-500 hover:bg-white/5'}`}
                  title={member.is_active ? 'Deactivate' : 'Activate'}
                >
                  {member.is_active ? <ToggleRight size={24} /> : <ToggleLeft size={24} />}
                </button>
                <button 
                  onClick={() => deleteStaff(member.id)}
                  className="p-2 text-zinc-600 hover:text-rose-500 hover:bg-rose-500/10 rounded-lg transition-colors"
                  title="Remove"
                >
                  <Trash2 size={20} />
                </button>
              </div>
            </div>
            {/* Busy Status Indicator Overlay */}
            {member.is_active && (
              <div className="absolute top-0 right-0 p-2">
                <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse shadow-[0_0_8px_rgba(16,185,129,0.5)]" />
              </div>
            )}
          </GlassCard>
        ))}
      </div>

      {staff.length === 0 && !showAddForm && (
        <div className="text-center py-20 border-2 border-dashed border-white/5 rounded-[2.5rem]">
           <Users size={40} className="text-zinc-800 mx-auto mb-4" />
           <p className="text-zinc-500 font-bold">No staff members added yet.</p>
           <button 
              onClick={() => setShowAddForm(true)}
              className="mt-4 text-[#00F5A0] text-xs font-black uppercase tracking-widest hover:brightness-110"
            >
              + Add your first operator
            </button>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Mail, ArrowRight, ShieldCheck, UserCircle } from "lucide-react";
import { createClient } from "@/lib/supabase/client";

const supabase = createClient();

interface FastAuthProps {
  onSuccess: (userId: string) => void;
  isModal?: boolean;
}

export default function FastAuth({ onSuccess, isModal = false }: FastAuthProps) {
  const [step, setStep] = useState<"email" | "otp" | "loading">("email");
  const [email, setEmail] = useState("");
  const [otp, setOtp] = useState(["", "", "", "", "", ""]);
  const [error, setError] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Real OTP Send
  const handleSendOtp = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!email || !email.includes('@')) {
      setError('Please enter a valid email address');
      return;
    }

    setError("");
    setIsSubmitting(true);
    setStep("loading");

    try {
      const { error: authError } = await supabase.auth.signInWithOtp({
        email,
        options: {
          shouldCreateUser: true,
        }
      });

      if (authError) {
        if (authError.message.includes('429')) {
          setError("Too many attempts. Please wait a minute.");
        } else {
          setError(authError.message);
        }
        setStep("email");
      } else {
        setStep("otp");
      }
    } catch (err: any) {
      setError(err.message);
      setStep("email");
    } finally {
      setIsSubmitting(false);
    }
  };

  // Real OTP Verify
  const handleVerifyOtp = async (e: React.FormEvent) => {
    e.preventDefault();
    const code = otp.join("");
    if (code.length < 6) return;

    setIsSubmitting(true);
    setStep("loading");

    try {
       const { data, error: verifyErr } = await supabase.auth.verifyOtp({
          email,
          token: code,
          type: 'email'
       });
       if (verifyErr) {
          if (verifyErr.message.includes('429')) {
             throw new Error("Too many attempts. Please wait a minute.");
          }
          throw verifyErr;
       }
       if (data.user) onSuccess(data.user.id);
    } catch (err: any) {
       setError(err.message);
       setStep("otp");
    } finally {
       setIsSubmitting(false);
    }
  };

  // Real Guest Login Trigger (Emergency Fallback)
  const handleGuestLogin = async () => {
    setStep("loading");
    try {
      const { data, error } = await supabase.auth.signInAnonymously();
      if (error) throw error;
      if (data.user) onSuccess(data.user.id);
    } catch (err: any) {
      setError(err.message);
      setStep("email");
    }
  };

  const wrapClasses = isModal 
    ? "bg-white dark:bg-slate-900 rounded-3xl shadow-2xl border border-slate-200 dark:border-slate-800 p-8 w-full max-w-md mx-auto overflow-hidden relative"
    : "w-full max-w-md mx-auto";

  return (
    <div className={wrapClasses}>
      <AnimatePresence mode="wait">

        {step === "email" && (
          <motion.div 
            key="email"
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: 20 }}
            className="flex flex-col h-full"
          >
            <div className="text-center mb-8">
              <div className="w-16 h-16 bg-gradient-to-tr from-indigo-500 to-purple-600 rounded-2xl flex items-center justify-center mx-auto mb-6 shadow-xl shadow-indigo-500/20">
                <ShieldCheck className="text-white w-8 h-8" />
              </div>
              <h2 className="text-2xl font-black text-slate-900 dark:text-white mb-2">Join the Queue</h2>
              <p className="text-slate-500 dark:text-slate-400">Enter your email to receive a secure join code instantly.</p>
            </div>

            <form onSubmit={handleSendOtp} className="space-y-6">
              <div>
                <div className="relative flex items-center">
                  <input
                    type="email"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    placeholder="you@email.com"
                    className="w-full bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl py-4 px-4 font-bold text-lg text-slate-900 dark:text-white placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all"
                    autoFocus
                  />
                  <Mail className="absolute right-4 text-slate-400" size={20} />
                </div>
                {error && <p className="text-rose-500 text-sm font-medium mt-2 text-center">{error}</p>}
              </div>

              <button 
                type="submit"
                disabled={!email || isSubmitting}
                className="w-full bg-slate-900 dark:bg-white text-white dark:text-slate-900 py-4 rounded-xl font-bold text-lg hover:shadow-lg disabled:opacity-50 disabled:cursor-not-allowed transition-all active:scale-95 flex items-center justify-center gap-2"
              >
                {isSubmitting ? "Sending OTP..." : <><span className="flex items-center gap-2">Send Join Code <ArrowRight size={20} /></span></>}
              </button>
            </form>

            <div className="mt-8 relative flex items-center justify-center">
               <div className="absolute inset-x-0 h-px bg-slate-200 dark:bg-slate-800" />
               <span className="bg-white dark:bg-slate-900 px-4 text-sm text-slate-400 font-medium relative z-10">or in an emergency</span>
            </div>

            <button 
              onClick={handleGuestLogin}
              disabled={isSubmitting}
              className="mt-8 w-full bg-indigo-50 dark:bg-indigo-500/10 text-indigo-700 dark:text-indigo-400 py-4 rounded-xl font-bold hover:bg-indigo-100 dark:hover:bg-indigo-500/20 flex items-center justify-center gap-2 transition-colors active:scale-95 border border-indigo-100 dark:border-indigo-500/20 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              <UserCircle size={20} />
              Continue as Guest
            </button>
          </motion.div>
        )}

        {step === "otp" && (
          <motion.div 
            key="otp"
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: 20 }}
            className="flex flex-col h-full"
          >
            <div className="text-center mb-10">
              <h2 className="text-2xl font-black text-slate-900 dark:text-white mb-2">Check Email</h2>
              <p className="text-slate-500 dark:text-slate-400">
                We sent a 6-digit code to <br/>
                <strong className="text-slate-900 dark:text-white">{email}</strong>
              </p>
            </div>

            <form onSubmit={handleVerifyOtp} className="space-y-8">
              <div className="flex justify-center gap-2 sm:gap-4">
                {otp.map((digit, index) => (
                  <input
                    key={index}
                    id={`otp-${index}`}
                    type="text"
                    inputMode="numeric"
                    maxLength={6} // Allow paste directly into first field
                    value={digit}
                    onChange={(e) => {
                      const val = e.target.value.replace(/\D/g, '');
                      if (val.length > 1) {
                        // Handle paste
                        const pasted = val.slice(0, 6).split('');
                        const newOtp = [...otp];
                        pasted.forEach((char, idx) => {
                          if (idx < 6) newOtp[idx] = char;
                        });
                        setOtp(newOtp);
                        document.getElementById(`otp-${Math.min(5, pasted.length)}`)?.focus();
                        return;
                      }
                      const newOtp = [...otp];
                      newOtp[index] = val;
                      setOtp(newOtp);
                      // Auto-advance
                      if (val && index < 5) {
                        document.getElementById(`otp-${index + 1}`)?.focus();
                      }
                    }}
                    onKeyDown={(e) => {
                      if (e.key === 'Backspace' && !otp[index] && index > 0) {
                        document.getElementById(`otp-${index - 1}`)?.focus();
                      }
                    }}
                    disabled={isSubmitting}
                    className="w-12 h-14 sm:w-16 sm:h-16 text-center text-2xl font-black bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-xl text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-indigo-500 disabled:opacity-50"
                    autoFocus={index === 0}
                  />
                ))}
              </div>

              {error && <p className="text-rose-500 text-sm font-medium mt-2 text-center">{error}</p>}

              <button 
                type="submit"
                disabled={otp.join("").length < 6 || isSubmitting}
                className="w-full bg-slate-900 dark:bg-white text-white dark:text-slate-900 py-4 rounded-xl font-bold text-lg hover:shadow-lg disabled:opacity-50 disabled:cursor-not-allowed transition-all active:scale-95"
              >
                {isSubmitting ? "Verifying..." : "Verify & Join Queue"}
              </button>
            </form>

            <button 
              onClick={() => setStep("email")}
              className="mt-6 text-sm flex items-center justify-center font-bold text-indigo-600 dark:text-indigo-400 hover:text-indigo-700"
            >
              Change Email Address
            </button>
          </motion.div>
        )}

        {step === "loading" && (
          <motion.div 
            key="loading"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="flex flex-col h-full items-center justify-center py-12"
          >
            <div className="relative w-24 h-24 mb-6">
               <div className="absolute inset-0 rounded-full border-4 border-slate-100 dark:border-slate-800" />
               <motion.div 
                 className="absolute inset-0 rounded-full border-4 border-indigo-500 border-t-transparent"
                 animate={{ rotate: 360 }}
                 transition={{ duration: 1, repeat: Infinity, ease: "linear" }}
               />
               <div className="absolute inset-0 flex items-center justify-center">
                 <ShieldCheck className="text-indigo-500 w-8 h-8" />
               </div>
            </div>
            <h3 className="font-bold text-xl text-slate-900 dark:text-white">Authenticating...</h3>
            <p className="text-slate-500 text-sm mt-2">Securing your session</p>
          </motion.div>
        )}

      </AnimatePresence>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { Zap, Loader2, AlertCircle } from 'lucide-react';

declare global {
  interface Window {
    Razorpay: any;
  }
}

interface FastPassCheckoutProps {
  businessId: string;
  businessName: string;
  amount: number;
  tokenData: any;
  onSuccess: (data: { tokenId: string; tokenNumber: string }) => void;
  onError: (error: string) => void;
  isLoading?: boolean;
}

export default function FastPassCheckout({
  businessId,
  businessName,
  amount,
  tokenData,
  onSuccess,
  onError,
  isLoading: externalLoading = false
}: FastPassCheckoutProps) {
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    // Load Razorpay Script
    const script = document.createElement('script');
    script.src = 'https://checkout.razorpay.com/v1/checkout.js';
    script.async = true;
    document.body.appendChild(script);

    return () => {
      document.body.removeChild(script);
    };
  }, []);

  const handlePayment = async () => {
    setLoading(true);
    try {
      // 1. Create Order
      const orderResp = await fetch('/api/create-fastpass-order', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ amount, businessId, businessName }),
      });
      
      const orderData = await orderResp.json();
      if (orderData.error) throw new Error(orderData.error);

      // 2. Open Razorpay Modal
      const options = {
        key: process.env.NEXT_PUBLIC_RAZORPAY_KEY_ID, // Public key
        amount: orderData.amount,
        currency: orderData.currency,
        name: "QueueLess India",
        description: `Fast Pass for ${businessName}`,
        order_id: orderData.orderId,
        handler: async function (response: any) {
          try {
            // 3. Verify Payment
            setLoading(true);
            const verifyResp = await fetch('/api/verify-fastpass-payment', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({
                razorpay_order_id: response.razorpay_order_id,
                razorpay_payment_id: response.razorpay_payment_id,
                razorpay_signature: response.razorpay_signature,
                tokenData: { ...tokenData, amount }
              }),
            });
            
            const verifyData = await verifyResp.json();
            if (verifyData.error) throw new Error(verifyData.error);
            
            onSuccess(verifyData);
          } catch (err: any) {
            onError(err.message || 'Payment verification failed');
          } finally {
            setLoading(false);
          }
        },
        prefill: {
          name: tokenData.customerName,
          contact: tokenData.customerPhone,
        },
        theme: {
          color: "#00F5A0",
        },
      };

      const rzp = new window.Razorpay(options);
      rzp.on('payment.failed', function (response: any) {
        onError(response.error.description || 'Payment failed');
      });
      rzp.open();

    } catch (err: any) {
      onError(err.message || 'Failed to initialize payment');
    } finally {
      setLoading(false);
    }
  };

  return (
    <button
      onClick={handlePayment}
      disabled={loading || externalLoading}
      className="flex-1 bg-gradient-to-r from-amber-400 to-orange-500 text-black font-black py-4 rounded-[1.5rem] shadow-xl hover:scale-105 active:scale-95 transition-all flex flex-col items-center justify-center gap-1 group relative overflow-hidden"
    >
      <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300" />
      <div className="flex items-center gap-2 relative z-10">
        <Zap size={18} className="fill-current animate-pulse" />
        <span className="text-lg">Fast Pass Γé╣{amount}</span>
      </div>
      <span className="text-[10px] uppercase tracking-tighter opacity-80 relative z-10">Jump to Front of Queue</span>
      {(loading || externalLoading) && (
        <div className="absolute inset-0 bg-zinc-900/50 bg-opacity-95 flex items-center justify-center z-20">
          <Loader2 size={24} className="animate-spin text-white" />
        </div>
      )}
    </button>
  );
}

"use client";

import { useEffect, useState } from "react";
import { MapPin, AlertTriangle } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";

interface GeoTrackerProps {
  hubLat: number;
  hubLng: number;
  isActiveToken: boolean;
}

// Haversine formula to calculate distance in KM between two coordinates
function getDistanceFromLatLonInKm(lat1: number, lon1: number, lat2: number, lon2: number) {
  const R = 6371; // Radius of the earth in km
  const dLat = (lat2 - lat1) * (Math.PI / 180);
  const dLon = (lon2 - lon1) * (Math.PI / 180);
  const a =
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(lat1 * (Math.PI / 180)) * Math.cos(lat2 * (Math.PI / 180)) * Math.sin(dLon / 2) * Math.sin(dLon / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
}

export default function GeoTracker({ hubLat, hubLng, isActiveToken }: GeoTrackerProps) {
  const [distanceKm, setDistanceKm] = useState<number | null>(null);
  const [permissionGranted, setPermissionGranted] = useState(false);
  const MAX_RADIUS_KM = 1.5; // Trigger warning if user wanders 1.5km away

  useEffect(() => {
    // We only track actively if they hold a token
    if (!isActiveToken || !("geolocation" in navigator)) return;

    const watchId = navigator.geolocation.watchPosition(
      (position) => {
        setPermissionGranted(true);
        const dist = getDistanceFromLatLonInKm(
          hubLat,
          hubLng,
          position.coords.latitude,
          position.coords.longitude
        );
        setDistanceKm(dist);
      },
      (error) => {
        console.log("Geo tracking denied or unavailable", error);
        setPermissionGranted(false);
      },
      { enableHighAccuracy: false, maximumAge: 30000, timeout: 27000 }
    );

    return () => navigator.geolocation.clearWatch(watchId);
  }, [isActiveToken, hubLat, hubLng]);

  // If they are safely within bounds or haven't granted permission, render nothing
  const isOutOfBounds = distanceKm !== null && distanceKm > MAX_RADIUS_KM;

  return (
    <AnimatePresence>
      {isOutOfBounds && (
        <motion.div 
          initial={{ opacity: 0, y: 50, scale: 0.95 }}
          animate={{ opacity: 1, y: 0, scale: 1 }}
          exit={{ opacity: 0, scale: 0.9 }}
          className="fixed bottom-6 left-1/2 -translate-x-1/2 w-[90%] max-w-sm z-[200]"
        >
          <div className="bg-rose-600 border border-rose-400 rounded-2xl shadow-2xl p-4 flex gap-4 items-start text-white">
            <div className="p-2 bg-rose-500 rounded-full shrink-0">
              <AlertTriangle size={24} />
            </div>
            <div>
              <h4 className="font-bold text-lg mb-1 flex items-center gap-2">
                <MapPin size={16} /> Distance Warning
              </h4>
              <p className="text-sm font-medium opacity-90">
                You appear to be {distanceKm?.toFixed(1)}km away from the center. Please head back to ensure you do not miss your token call.
              </p>
            </div>
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}

