"use client";

import { useState, useEffect, useCallback } from "react";

const SESSION_KEY = "queueless_guest_sessions";
const SESSION_TTL_MS = 24 * 60 * 60 * 1000; // 24 hours

interface GuestVisit {
  businessId: string;
  name: string;
  phone: string;
  activeTokenId: string | null;
  activeTokenNumber: string | null;
  timestamp: number;
}

interface GuestSessionStore {
  [businessId: string]: GuestVisit;
}

function readStore(): GuestSessionStore {
  if (typeof window === "undefined") return {};
  try {
    return JSON.parse(localStorage.getItem(SESSION_KEY) || "{}");
  } catch {
    return {};
  }
}

function writeStore(store: GuestSessionStore) {
  if (typeof window === "undefined") return;
  localStorage.setItem(SESSION_KEY, JSON.stringify(store));
}

function pruneExpired(store: GuestSessionStore): GuestSessionStore {
  const now = Date.now();
  return Object.fromEntries(
    Object.entries(store).filter(([, v]) => now - v.timestamp < SESSION_TTL_MS)
  );
}

export function useGuestSession(businessId: string) {
  const [guestVisit, setGuestVisit] = useState<GuestVisit | null>(null);
  const [isLoaded, setIsLoaded] = useState(false);

  useEffect(() => {
    // Only runs client-side
    const store = pruneExpired(readStore());
    writeStore(store); // persist pruned
    const visit = store[businessId] || null;
    setGuestVisit(visit);
    setIsLoaded(true);
  }, [businessId]);

  const saveGuestSession = useCallback((data: {
    name: string;
    phone: string;
    activeTokenId?: string;
    activeTokenNumber?: string;
  }) => {
    const store = pruneExpired(readStore());
    store[businessId] = {
      businessId,
      name: data.name,
      phone: data.phone,
      activeTokenId: data.activeTokenId || null,
      activeTokenNumber: data.activeTokenNumber || null,
      timestamp: Date.now(),
    };
    writeStore(store);
    setGuestVisit(store[businessId]);
  }, [businessId]);

  const updateToken = useCallback((tokenId: string, tokenNumber: string) => {
    const store = pruneExpired(readStore());
    if (store[businessId]) {
      store[businessId].activeTokenId = tokenId;
      store[businessId].activeTokenNumber = tokenNumber;
      store[businessId].timestamp = Date.now(); // refresh TTL
      writeStore(store);
      setGuestVisit({ ...store[businessId] });
    }
  }, [businessId]);

  const clearSession = useCallback(() => {
    const store = readStore();
    delete store[businessId];
    writeStore(store);
    setGuestVisit(null);
  }, [businessId]);

  // Global helper: get any guest token from any recent visit
  const getAllSessions = useCallback((): GuestVisit[] => {
    const store = pruneExpired(readStore());
    return Object.values(store);
  }, []);

  return {
    guestVisit,
    isLoaded,
    guestName: guestVisit?.name || "",
    guestPhone: guestVisit?.phone || "",
    activeTokenId: guestVisit?.activeTokenId || null,
    activeTokenNumber: guestVisit?.activeTokenNumber || null,
    isReturningGuest: !!guestVisit,
    saveGuestSession,
    updateToken,
    clearSession,
    getAllSessions,
  };
}

"use client";

import { useEffect, useState } from "react";
import { createClient } from "@/lib/supabase/client";
import { Token } from "@/types/database";

/**
 * Real-time queue subscription hook.
 * Subscribes to live INSERT/UPDATE/DELETE events on the `tokens` table
 * for a given queueId, keeping the token list in sync without polling.
 */
export function useQueueRealtime(queueId: string) {
  const [tokens, setTokens] = useState<Token[]>([]);
  const supabase = createClient();

  useEffect(() => {
    if (!queueId) return;

    // Initial fetch
    supabase
      .from("tokens")
      .select("*")
      .eq("queue_id", queueId)
      .order("createdAt", { ascending: true })
      .then(({ data }) => setTokens(data || []));

    // Subscribe to real-time changes
    const channel = supabase
      .channel(`queue-${queueId}`)
      .on(
        "postgres_changes",
        {
          event: "*",
          schema: "public",
          table: "tokens",
          filter: `queue_id=eq.${queueId}`,
        },
        (payload) => {
          if (payload.eventType === "INSERT") {
            setTokens((prev) => [...prev, payload.new as Token]);
          } else if (payload.eventType === "UPDATE") {
            setTokens((prev) =>
              prev.map((t) => (t.id === payload.new.id ? (payload.new as Token) : t))
            );
          } else if (payload.eventType === "DELETE") {
            setTokens((prev) => prev.filter((t) => t.id !== (payload.old as Token).id));
          }
        },
      );

    const handleVisibility = () => {
      if (document.hidden) {
        channel.unsubscribe();
      } else {
        channel.subscribe();
      }
    };

    channel.subscribe();
    document.addEventListener("visibilitychange", handleVisibility);

    return () => {
      document.removeEventListener("visibilitychange", handleVisibility);
      supabase.removeChannel(channel);
    };
  }, [queueId]);

  return tokens;
}

export const track = (eventName: string, data?: Record<string, string | number>) => {
  if (typeof window !== 'undefined' && (window as any).umami) {
    (window as any).umami.track(eventName, data)
  }
}

/**
 * Utility for Web Notifications API
 */

export const requestNotificationPermission = async () => {
  if (!('Notification' in window)) {
    console.warn('Notifications not supported');
    return false;
  }

  if (Notification.permission === 'granted') return true;

  const permission = await Notification.requestPermission();
  return permission === 'granted';
};

export const sendTokenAlert = (position: number, businessName?: string) => {
  if (!('Notification' in window) || Notification.permission !== 'granted') {
    return;
  }

  const message = position === 0 
    ? "It's your turn now! Please proceed to the counter." 
    : `You're #${position} in queue${businessName ? ` at ${businessName}` : ''}!`;

  new Notification('Queue Update - QueueLess India', {
    body: message,
    icon: '/icon-192.png',
    badge: '/icon-192.png',
