import { useState, useEffect } from 'react';
import { createClient } from '@/lib/supabase/client';

const supabase = createClient();

export interface AIPrediction {
  bestTimeToVisit: string;
  currentWaitTime: number; // in mins
  predictedWaitNextHour: number; // in mins
  predictedPeakHours: string;
  confidence: string;
}

export function useAIPrediction(orgId: string, stats: { currentlyWaiting: number, totalToday: number }) {
  const [prediction, setPrediction] = useState<AIPrediction | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (!orgId) return;

    const generateOrFetchPrediction = async () => {
      setLoading(true);
      setError(null);
      try {
        // predictions.id = businesses.id (slug)
        const predictionId = orgId;

        // 1. Try to fetch from Supabase first
        const { data: cachedPred, error: fetchErr } = await supabase
          .from('predictions')
          .select('*')
          .eq('id', predictionId)
          .maybeSingle();

        if (cachedPred && !fetchErr) {
          setPrediction(cachedPred as unknown as AIPrediction);
        } else {
          // 2. Call secure Edge Function if no cached version exists
          const { data: generatedData, error: edgeErr } = await supabase.functions.invoke('predict-queue', {
            body: { orgId, stats }
          });

          if (edgeErr) throw edgeErr;

          setPrediction(generatedData as AIPrediction);
        }
      } catch (err) {
        console.error("Prediction error:", err);
        setError("Failed to load predictions.");

        // Fallback
        setPrediction({
          bestTimeToVisit: "10:00 AM - 11:30 AM",
          currentWaitTime: stats.currentlyWaiting > 0 ? stats.currentlyWaiting * 4 : 5,
          predictedWaitNextHour: Math.floor(Math.random() * 20) + 15,
          predictedPeakHours: "5:00 PM - 7:00 PM",
          confidence: "High (Mocked Fallback)"
        });
      } finally {
        setLoading(false);
      }
    };

    generateOrFetchPrediction();

  }, [orgId, stats.currentlyWaiting, stats.totalToday]);

  return { prediction, loading, error };
}

import { useEffect, useState } from "react";
import { createClient } from "@/lib/supabase/client";
import { Token as TokenItem } from "@/types/database";

export const useAdminQueue = (orgId: string, counterId?: string) => {
  const supabase = createClient();
  const [queue, setQueue] = useState<TokenItem[]>([]);
  const [currentlyServing, setCurrentlyServing] = useState<TokenItem | null>(
    null,
  );
  const [stats, setStats] = useState({
    totalToday: 0,
    currentlyWaiting: 0,
    served: 0,
  });

  useEffect(() => {
    if (!orgId) return;

    const fetchAdminData = async () => {
      if (orgId.startsWith("demo-")) {
        mockData();
        return;
      }
      try {
        // 1. Fetch active queue stats
        let queuesQuery = (supabase
          .from("queues") as any)
          .select("*")
          .eq("org_id", orgId)
          .eq("session_date", new Date().toISOString().split("T")[0]);

        if (counterId) {
          queuesQuery = queuesQuery.eq("counter_id", counterId);
        }

        const { data: queueRows, error: qErr } = await queuesQuery;

        if (qErr && qErr.code !== "PGRST116") throw qErr;

        // 2. Fetch the active tokens list (WAITING & SERVING)
        let query = (supabase
          .from("tokens") as any)
          .select("*")
          .eq("orgId", orgId)
          .in("status", ["WAITING", "SERVING"])
          .order("createdAt", { ascending: true });

        if (counterId) {
          query = query.eq("counterId", counterId);
        }

        const { data: activeTokens, error: tokensErr } = await query;
        if (tokensErr) throw tokensErr;

        // 3. Process the state
        const fullQueue: TokenItem[] = (activeTokens as TokenItem[]) || [];
        let serving: TokenItem | null = null;
        let waitingCount = 0;

        fullQueue.forEach((data) => {
          if (data.status === "SERVING") serving = data;
          if (data.status === "WAITING") waitingCount++;
        });

        setQueue(fullQueue);
        setCurrentlyServing(serving);

        // Derive stats directly from the queues row to save counting
        if (queueRows && queueRows.length > 0) {
          let totalIssued = 0;
          queueRows.forEach((row: any) =>
            totalIssued += row.last_issued_number || 0
          );

          setStats({
            totalToday: totalIssued,
            currentlyWaiting: waitingCount, // Derived from active tokens
            served: totalIssued - waitingCount - (serving ? 1 : 0),
          });
        } else {
          setStats({ totalToday: 0, currentlyWaiting: 0, served: 0 });
        }
      } catch (err) {
        console.warn("Supabase fetch failed, falling back to mock", err);
        mockData();
      }
    };

    fetchAdminData();

    // Setup Realtime Subscriptions
    // Listen to changes on the tokens table (new joins, status updates)
    const tokensChannel = supabase
      .channel(`admin-tokens-${orgId}`)
      .on(
        "postgres_changes",
        {
          event: "*",
          schema: "public",
          table: "tokens",
          filter: `orgId=eq.${orgId}`,
        },
        () => fetchAdminData(),
      )
      .subscribe();

    return () => {
      supabase.removeChannel(tokensChannel);
    };

    function mockData() {
      setCurrentlyServing({
        id: "1",
        orgId,
        counterId: counterId || "opd",
        userId: "",
        customerName: "Rahul S.",
        tokenNumber: "OPD-011",
        status: "SERVING",
        createdAt: new Date().toISOString(),
        estimatedWaitMins: 0,
        queue_id: 'q1',
        isPriority: false,
        servedAt: null,
        customerPhone: null
      });
      setQueue([
        {
          id: "2",
          orgId,
          counterId: "opd",
          userId: "",
          customerName: "Anjali M.",
          tokenNumber: "OPD-012",
          status: "WAITING",
          createdAt: new Date().toISOString(),
          estimatedWaitMins: 5,
          queue_id: 'q1',
          isPriority: false,
          servedAt: null,
          customerPhone: null
        },
        {
          id: "3",
          orgId,
          counterId: "opd",
          userId: "",
          customerName: "Vikram K.",
          tokenNumber: "OPD-013",
          status: "WAITING",
          createdAt: new Date().toISOString(),
          estimatedWaitMins: 10,
          queue_id: 'q1',
          isPriority: false,
          servedAt: null,
          customerPhone: null
        },
      ]);
      setStats({ totalToday: 142, currentlyWaiting: 2, served: 118 });
    }
  }, [orgId, counterId]);

  return { queue, currentlyServing, stats };
};

import { useEffect, useState } from "react";
import { createClient } from "@/lib/supabase/client";
import { Token } from "@/types/database";

export const useCustomerQueue = (orgId: string, tokenNumber: string | null) => {
  const supabase = createClient();
  const [ticketStatus, setTicketStatus] = useState<Token['status'] | null>(null);
  const [currentlyServing, setCurrentlyServing] = useState<string>("Wait...");
  const [peopleAhead, setPeopleAhead] = useState(0);
  const [estimatedWait, setEstimatedWait] = useState(0);

  useEffect(() => {
    if (!orgId || !tokenNumber) return;

    // Helper to get prefix (e.g., 'OPD' from 'OPD-011')
    const prefix = tokenNumber.split("-")[0].toLowerCase();

    const fetchQueueState = async () => {
      try {
        // 1. Fetch the user's specific token for status
        const { data: tokenData, error: tokenErr } = await supabase
          .from("tokens")
          .select("*")
          .eq("orgId", orgId)
          .eq("tokenNumber", tokenNumber)
          .maybeSingle();

        if (tokenErr) throw tokenErr;

        if (tokenData) {
          setTicketStatus((tokenData as Token).status);
          setEstimatedWait((tokenData as Token).estimatedWaitMins || 0);
        }

        // 2. Fetch the aggregate queue row for currently serving & people ahead calculation
        if (tokenData && tokenData.queue_id) {
          const { data: queueData, error: qErr } = await supabase
            .from("queues")
            .select(
              "last_issued_number, currently_serving_token_id, total_waiting",
            )
            .eq("id", tokenData.queue_id)
            .maybeSingle();

          if (!qErr && queueData) {
            // If there's an active serving token, fetch its number just for display
            if (queueData.currently_serving_token_id) {
              const { data: activeToken } = await supabase
                .from("tokens")
                .select("tokenNumber")
                .eq("id", queueData.currently_serving_token_id)
                .maybeSingle();

              if (activeToken) setCurrentlyServing(activeToken.tokenNumber);
            } else {
              setCurrentlyServing("Wait...");
            }

            // Simplified 'people ahead' calculation using the active tokens ID vs this users ID
            // In a production app, this would be computed on the server side or by difference in token numbers
            // For this MVP, we just use the raw tokens rank since tokenNumber is sequential 'OPD-001'
            const myNum = parseInt(tokenNumber.split("-")[1] || "0", 10);
            let servingNum = 0;
            if (queueData.currently_serving_token_id) {
              const { data: activeToken } = await supabase
                .from("tokens")
                .select("tokenNumber")
                .eq("id", queueData.currently_serving_token_id)
                .maybeSingle();
              servingNum = parseInt(
                activeToken?.tokenNumber?.split("-")[1] || "0",
                10,
              );
            }

            const ahead = Math.max(0, myNum - servingNum - 1);
            if (tokenData.status === "WAITING") {
              setPeopleAhead(ahead);
            } else {
              setPeopleAhead(0);
            }
          }
        }
      } catch (err) {
        console.warn("Supabase customer fetch failed, using mock data", err);
        applyMockData();
      }
    };

    fetchQueueState();

    // Setup Realtime Subscriptions
    // 1. Subscribe to their own token for status changes (WAITING -> SERVING)
    const tokenChannel = supabase
      .channel(`customer-token-${tokenNumber}`)
      .on(
        "postgres_changes",
        {
          event: "UPDATE",
          schema: "public",
          table: "tokens",
          filter: `tokenNumber=eq.${tokenNumber}`,
        },
        () => fetchQueueState(),
      );

    // 2. Subscribe to the queues table for movement in the line
    const queueChannel = supabase
      .channel(`queue-aggregate-${orgId}`)
      .on(
        "postgres_changes",
        {
          event: "UPDATE",
          schema: "public",
          table: "queues",
          filter: `org_id=eq.${orgId}`,
        },
        () => fetchQueueState(),
      );

    const handleVisibility = () => {
      if (document.hidden) {
        tokenChannel.unsubscribe();
        queueChannel.unsubscribe();
      } else {
        tokenChannel.subscribe();
        queueChannel.subscribe();
      }
    };

    tokenChannel.subscribe();
    queueChannel.subscribe();
    document.addEventListener("visibilitychange", handleVisibility);

    return () => {
      document.removeEventListener("visibilitychange", handleVisibility);
      supabase.removeChannel(tokenChannel);
      supabase.removeChannel(queueChannel);
    };

    function applyMockData() {
      setCurrentlyServing("OPD-011");
      setPeopleAhead(3);
      setTicketStatus("WAITING");
      setEstimatedWait(15);
    }
  }, [orgId, tokenNumber]);

  return { ticketStatus, currentlyServing, peopleAhead, estimatedWait };
};
